import { RouterModule, Routes } from '@angular/router';

import { AdminContainerComponent } from './components/admin-container/admin-container.component';
import { NgModule } from '@angular/core';
import { clientResolver } from './resolvers/client.resolver';
import { distributorResolver } from './resolvers/distributor.resolver';
import { vendorResolver } from './resolvers/vendor.resolver';

const routes: Routes = [
  {
    path: '',
    component: AdminContainerComponent,
    children: [
      {
        path: 'vendor/:vendorId',
        resolve: {
          vendor: vendorResolver,
        },
        loadChildren: () =>
          import('./components/vendors/vendors.module').then(
            (m) => m.VendorsModule,
          ),
      },
      {
        path: 'distributor/:distributorId',
        resolve: {
          distributor: distributorResolver,
        },
        loadChildren: () =>
          import('./components/distributors/distributors.module').then(
            (m) => m.DistributorsModule,
          ),
      },
      {
        path: 'client/:clientId',
        resolve: {
          client: clientResolver,
        },
        loadChildren: () =>
          import('./components/clients/clients.module').then(
            (m) => m.ClientsModule,
          ),
      },
    ],
  },
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule],
})
export class AdministrationRoutingModule {}
