import {
  AfterViewInit,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  DeviceConfigProfileCreateRequest,
  DeviceConfigProfileResponse,
} from '../../../../../api';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { DeviceConfigProfileDetailsSectionComponent } from '../device-config-profile-details-section/device-config-profile-details-section.component';
import { Step } from '../../../../../shared/models';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';

@Component({
  selector: 'app-device-config-profile-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    DeviceConfigProfileDetailsSectionComponent,
  ],
  templateUrl: './device-config-profile-create-wizard.component.html',
  styleUrl: './device-config-profile-create-wizard.component.scss',
})
export class DeviceConfigProfileCreateWizardComponent
  implements AfterViewInit, OnInit
{
  @ViewChild('deviceConfigProfileDetailsStep')
  deviceConfigProfileDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;

  // References to form components
  @ViewChild('deviceConfigProfileDetailsForm')
  deviceConfigProfileDetailsForm!: DeviceConfigProfileDetailsSectionComponent;

  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);

  // DeviceConfigProfile model to collect data across steps
  newDeviceConfigProfile = signal<DeviceConfigProfileCreateRequest>(
    {} as DeviceConfigProfileCreateRequest,
  );

  // Form validity state
  formIsValid = signal<boolean>(false);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    setTimeout(() => {
      this.steps = [
        {
          value: 1,
          header: 'Device Config Profile Details',
          content: this.deviceConfigProfileDetailsStep,
          complete: false,
          validate: () => this.deviceConfigProfileDetailsForm.validate(),
        },
        {
          value: 2,
          header: 'Confirmation',
          content: this.confirmationTemplate,
          complete: true,
        },
      ];
    });
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize deviceConfigProfile with ownerId
      this.newDeviceConfigProfile.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  openWizard() {
    this.displayWizard = true;
    this.newDeviceConfigProfile.set({} as DeviceConfigProfileCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  updateDeviceConfigProfileDetails(formData: Record<string, unknown>) {
    this.newDeviceConfigProfile.update((current) => {
      const { ownerId: _ownerId, ...rest } = formData;
      const updated = { ...current, ...rest };

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  onWizardComplete(): void {
    const deviceConfigProfileData = this.newDeviceConfigProfile();

    if (
      isNullOrUndefined(deviceConfigProfileData) ||
      Object.keys(deviceConfigProfileData).length === 0
    ) {
      return;
    }

    this.entitiesService
      .createDeviceConfigProfile(deviceConfigProfileData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: DeviceConfigProfileResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'device-config-profile',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newDeviceConfigProfile.set({} as DeviceConfigProfileCreateRequest);
    this.dialogRef.close();
  }
}
