import { Component, input, output } from '@angular/core';
import { TreeNode } from 'primeng/api';
import { TreeModule, TreeNodeExpandEvent } from 'primeng/tree';

@Component({
  selector: 'app-tree-panel',
  standalone: true,
  imports: [TreeModule],
  templateUrl: './tree-panel.component.html',
  styleUrl: './tree-panel.component.scss',
})
export class TreePanelComponent {
  readonly nodes = input<TreeNode[]>([]);
  readonly selectionMode = input<'single' | 'multiple' | 'checkbox'>('single');
  readonly loading = input(false);
  readonly emptyMessage = input('No data available');
  readonly styleClass = input('');
  readonly selection = input<TreeNode | TreeNode[] | null>(null);

  readonly nodeSelect = output<TreeNode>();
  readonly nodeUnselect = output<TreeNode>();
  readonly nodeExpand = output<TreeNode>();
  readonly nodeCollapse = output<TreeNode>();

  onNodeSelect(event: { node: TreeNode }): void {
    this.nodeSelect.emit(event.node);
  }

  onNodeUnselect(event: { node: TreeNode }): void {
    this.nodeUnselect.emit(event.node);
  }

  onNodeExpand(event: TreeNodeExpandEvent): void {
    this.nodeExpand.emit(event.node);
  }

  onNodeCollapse(event: { node: TreeNode }): void {
    this.nodeCollapse.emit(event.node);
  }
}
