import { computed, inject, signal } from '@angular/core';
import {
  GridConfiguration,
  GridDataService,
  FilterCriteria,
  GridColumn,
  DataGridParams,
  FilterValue,
} from '../models';
import { UtilityService } from '../../core/services/utility.service';
import { GridBaseService } from './grid-base.service';
import { TableLazyLoadEvent } from 'primeng/table';
import { isDefined } from '../utils';
import { DEFAULT_PAGE_SIZE } from '../../core/models';

export abstract class BaseGridConfig<T> implements GridConfiguration<T> {
  protected readonly utilityService = inject(UtilityService);
  protected readonly gridBaseService = inject(GridBaseService);

  protected readonly filterState = signal<Record<string, FilterCriteria>>({});
  protected readonly defaultStateValues: string[] = [];
  protected params: Record<string, string> = {};

  protected readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );

  abstract columns: GridColumn<T>[];
  abstract dataService: GridDataService<T>;
  abstract getTitle(): string;

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({});
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    let sortField = 'name:asc';

    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: this.params['clientId'],
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: sortField,
      filters: this.rqlFilter(),
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const column = this.columns.find((col) => col.field === field);

    if (Array.isArray(value)) {
      // Use the same approach as non-array values for consistency
      const newFilters = this.gridBaseService.handleFilters(
        this.filterState(),
        field,
        value,
        undefined,
        column?.filterMatchMode,
      );

      this.filterState.set(newFilters);
      return;
    }

    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      field,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);
  }
}
