import { CommonModule } from '@angular/common';
import {
  AfterViewInit,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  IoTypeCreateRequest,
  IoTypeResponse,
} from '../../../../../api';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { IoTypeDetailsSectionComponent } from '../io-type-details-section/io-type-details-section.component';
import { Step } from '../../../../../shared/models';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { UtilityService } from '../../../../../core/services/utility.service';

@Component({
  selector: 'app-io-type-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    IoTypeDetailsSectionComponent,
  ],
  templateUrl: './io-type-create-wizard.component.html',
  styleUrl: './io-type-create-wizard.component.scss',
})
export class IoTypeCreateWizardComponent implements AfterViewInit, OnInit {
  @ViewChild('ioTypeDetailsStep') ioTypeDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;

  // References to form components
  @ViewChild('ioTypeDetailsForm')
  ioTypeDetailsForm!: IoTypeDetailsSectionComponent;

  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);
  private readonly utilityService = inject(UtilityService);

  // IoType model to collect data across steps
  newIoType = signal<IoTypeCreateRequest>({} as IoTypeCreateRequest);

  // Form validity state
  formIsValid = signal<boolean>(false);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngOnInit(): void {
    this.steps = [
      {
        value: 1,
        header: 'Io type Details',
        content: null,
        complete: false,
        validate: () => this.ioTypeDetailsForm?.validate(),
      },
      {
        value: 2,
        header: 'Confirmation',
        content: null,
        complete: true,
      },
    ];

    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      this.newIoType.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  ngAfterViewInit() {
    if (this.steps.length > 0 && this.ioTypeDetailsStep) {
      this.steps[0].content = this.ioTypeDetailsStep;
    }
    if (this.steps.length > 1 && this.confirmationTemplate) {
      this.steps[1].content = this.confirmationTemplate;
    }
  }

  openWizard() {
    this.displayWizard = true;
    this.newIoType.set({} as IoTypeCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  // Update the ioType state with form data
  updateIoTypeDetails(formData: Record<string, unknown>) {
    this.newIoType.update((current) => {
      const updated = { ...current };

      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  onWizardComplete(): void {
    // Process the final data from all steps
    const ioTypeData = this.newIoType();

    this.entitiesService
      .createIoType(ioTypeData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: IoTypeResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'iotype',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          // Handle error, could show message and keep dialog open
          console.error('Error creating IO type:', error);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newIoType.set({} as IoTypeCreateRequest);
    this.dialogRef.close();
  }

  decamelize(str: unknown): string {
    return this.utilityService.decamelize(str as string);
  }
}
