import { CommonModule } from '@angular/common';
import {
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';
import { Observable } from 'rxjs';

import {
  AccountsService,
  ClientResponse,
  CustomFieldDefinition,
  VendorResponse,
} from '../../../../../api';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { isDefined } from '../../../../../shared/utils';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { CustomFieldDetailsSectionComponent } from '../custom-field-details-section/custom-field-details-section.component';
import { Step } from '../../../../../shared/models';
import { firstValueFrom } from 'rxjs';

@Component({
  selector: 'app-custom-field-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    CustomFieldDetailsSectionComponent,
  ],
  templateUrl: './custom-field-create-wizard.component.html',
  styleUrl: './custom-field-create-wizard.component.scss',
})
export class CustomFieldCreateWizardComponent implements AfterViewInit, OnInit {
  @ViewChild('customFieldDetailsStep') customFieldDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;

  // References to form components
  @ViewChild('customFieldDetailsForm')
  customFieldDetailsForm!: CustomFieldDetailsSectionComponent;

  private readonly accountsService = inject(AccountsService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);
  private readonly cdr = inject(ChangeDetectorRef);

  // CustomField model to collect data across steps
  newCustomField = signal<CustomFieldDefinition>({} as CustomFieldDefinition);

  // Form validity state
  formIsValid = signal<boolean>(false);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    this.steps = [
      {
        value: 1,
        header: 'Custom Field Details',
        content: this.customFieldDetailsStep,
        complete: false,
        validate: () => this.customFieldDetailsForm.validate(),
      },
      {
        value: 2,
        header: 'Confirmation',
        content: this.confirmationTemplate,
        complete: true,
      },
    ];

    this.cdr.detectChanges();
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize customField with ownerId
      this.newCustomField.update((current) => ({
        ...current,
      }));
    }
  }

  openWizard() {
    this.displayWizard = true;
    this.newCustomField.set({} as CustomFieldDefinition);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  // Update the customField state with form data
  updateCustomFieldDetails(formData: Record<string, unknown>) {
    this.newCustomField.update((current) => {
      const updated = { ...current, ...formData } as CustomFieldDefinition;

      return updated;
    });
  }

  onWizardComplete(): void {
    firstValueFrom(this.accountsService.getCompany(this.ownerId ?? ''))
      .then((company) => {
        const customFieldData = {
          id: this.newCustomField()['tag'],
          title: this.newCustomField()['title'],
          type: this.newCustomField()['type'],
          required: this.newCustomField()['required'],
          values: this.newCustomField()['values']?.map((value) => ({
            key: value.key,
            value: value.value,
          })),
        };

        customFieldData.required = !!customFieldData.required;
        customFieldData.values = customFieldData.values ?? [];
        const customFields: Record<string, CustomFieldDefinition[]> =
          JSON.parse(JSON.stringify(company.customFields));
        const bucket =
          customFields[this.newCustomField()['entityType']['id']] ?? [];
        bucket.push(customFieldData);
        customFields[this.newCustomField()['entityType']['id']] = bucket;

        // Check for duplicate IDs
        // Helper to count duplicate custom field IDs
        function getDuplicateFieldCount(
          fields: Record<string, CustomFieldDefinition[]>,
          id: string,
        ): number {
          let count = 0;
          for (const arr of Object.values(fields)) {
            if (Array.isArray(arr)) {
              for (const x of arr) {
                if (x.id === id) count++;
              }
            }
          }
          return count;
        }

        const duplicateCount = getDuplicateFieldCount(
          customFields,
          customFieldData.id,
        );
        if (duplicateCount > 1) {
          throw new Error('A custom field with the same ID already exists');
        }

        const updateDetails$: Observable<ClientResponse | VendorResponse> =
          company.type === 'client'
            ? this.accountsService.updateClientDetails(
                this.ownerId ?? '',
                { customFields },
                'body',
              )
            : this.accountsService.updateVendorDetails(
                this.ownerId ?? '',
                { customFields },
                'body',
              );

        return updateDetails$
          .pipe(takeUntilDestroyed(this.destroyRef))
          .subscribe({
            next: (response: ClientResponse | VendorResponse) => {
              this.broadcastService.broadcast('entity-updated', {
                entityType: 'custom-field',
                operation: 'create',
                entityId: response.id,
              });
              this.dialogRef.close(response);
            },
            error: (error: Error) => {
              // Handle error, could show message and keep dialog open
              console.error('Error creating custom field:', error);
            },
          });
      })
      .catch(() => {});
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newCustomField.set({} as CustomFieldDefinition);
    this.dialogRef.close();
  }
}
