import {
  AfterViewInit,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  SmsGatewayProviderCreateRequest,
  SmsGatewayProviderResponse,
  SmsGatewayProviderTypeResponse,
} from '../../../../../api';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { SmsGatewayProviderDetailsSectionComponent } from '../sms-gateway-provider-details-section/sms-gateway-provider-details-section.component';
import { Step } from '../../../../../shared/models';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { SmsGatewayProviderParametersSectionComponent } from '../sms-gateway-provider-parameters-section/sms-gateway-provider-parameters-section.component';
import { RequestCacheService } from '../../../../../shared/services/request-cache.service';
import { firstValueFrom } from 'rxjs';
import { FormBuilderField } from '../../device/device-accessory-section/device-accessory-section.component';
import { ApiSchemaService } from '../../../../../core/services/api-schema.service';

@Component({
  selector: 'app-sms-gateway-provider-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    SmsGatewayProviderDetailsSectionComponent,
    SmsGatewayProviderParametersSectionComponent,
  ],
  templateUrl: './sms-gateway-provider-create-wizard.component.html',
  styleUrl: './sms-gateway-provider-create-wizard.component.scss',
})
export class SmsGatewayProviderCreateWizardComponent
  implements AfterViewInit, OnInit
{
  @ViewChild('smsGatewayProviderDetailsStep')
  smsGatewayProviderDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('smsGatewayProviderParametersStep')
  smsGatewayProviderParametersStep!: TemplateRef<{
    $implicit: Step;
  }>;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;

  // References to form components
  @ViewChild('smsGatewayProviderDetailsForm')
  smsGatewayProviderDetailsForm!: SmsGatewayProviderDetailsSectionComponent;
  @ViewChild('smsGatewayProviderParametersForm')
  smsGatewayProviderParametersForm!: SmsGatewayProviderParametersSectionComponent;
  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly cacheService = inject(RequestCacheService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);
  private readonly apiSchemaService = inject(ApiSchemaService);

  typePropertyKey =
    this.apiSchemaService.getTypePropertyKey('SmsGatewayProvider');

  // SmsGatewayProvider model to collect data across steps
  newSmsGatewayProvider = signal<SmsGatewayProviderCreateRequest>(
    {} as SmsGatewayProviderCreateRequest,
  );
  readonly smsGatewayProviderParametersFields = signal<
    { key: string; title: string }[] | null
  >(null);
  smsGatewayProviderType = signal<SmsGatewayProviderTypeResponse | null>(null);
  // Form validity state
  formIsValid = signal<boolean>(false);

  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    setTimeout(() => {
      // Only update the view-dependent properties
      this.steps[0].content = this.smsGatewayProviderDetailsStep;
      this.steps[0].validate = () =>
        this.smsGatewayProviderDetailsForm.validate();

      this.steps[1].content = this.smsGatewayProviderParametersStep;
      this.steps[1].validate = () =>
        this.smsGatewayProviderParametersForm.validate();

      this.steps[2].content = this.confirmationTemplate;
      this.steps[2].validate = () => true;
    });
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize smsGatewayProvider with ownerId
      this.newSmsGatewayProvider.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }

    this.steps = [
      {
        value: 1,
        header: 'SMS Gateway Provider Details',
        complete: false,
        content: null,
      },
      {
        value: 2,
        header: 'SMS Gateway Provider Parameters',
        content: null,
        complete: false,
      },
      {
        value: 3,
        header: 'Confirmation',
        complete: true,
        content: null,
      },
    ];
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  onParametersFormValidityChange(isValid: boolean) {
    this.steps[1].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  updateSmsGatewayProviderDetails(formData: Record<string, unknown>) {
    this.newSmsGatewayProvider.update((current) => {
      const { ownerId: _ownerId, ...rest } = formData;
      const updated = { ...current, ...rest };

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
    // Load the SMS Gateway Provider Type based on the selected type
    this.loadSmsGatewayProviderType(
      this.newSmsGatewayProvider()[this.typePropertyKey]?.id,
    ).catch(() => {});
  }

  updateSmsGatewayProviderParameters(formData: Record<string, unknown>) {
    this.newSmsGatewayProvider.update((current) => {
      const updated = {
        ...current,
        ...{ parameters: formData as Record<string, Record<string, unknown>> },
      };
      return updated;
    });
  }

  onWizardComplete(): void {
    const smsGatewayProviderData = this.newSmsGatewayProvider();

    if (
      isNullOrUndefined(smsGatewayProviderData) ||
      Object.keys(smsGatewayProviderData).length === 0
    ) {
      return;
    }

    this.entitiesService
      .createSmsGatewayProvider(smsGatewayProviderData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: SmsGatewayProviderResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'sms-gateway-provider',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newSmsGatewayProvider.set({} as SmsGatewayProviderCreateRequest);
    this.dialogRef.close();
  }

  async loadSmsGatewayProviderType(
    smsGatewayProviderTypeId: string | undefined,
  ): Promise<void> {
    if (isNullOrUndefined(smsGatewayProviderTypeId)) return;

    const response = await this.cacheService.getOrFetchAsync(
      `smsGatewayProviderType-${smsGatewayProviderTypeId}`,
      () =>
        firstValueFrom(
          this.entitiesService.getSmsGatewayProviderType(
            smsGatewayProviderTypeId,
          ),
        ),
      300000,
    );

    this.smsGatewayProviderType.set(response);
    const params: { groups: { fields: FormBuilderField[] }[] } = JSON.parse(
      response.parameterDefinition ?? '{"groups":[]}',
    );

    const values = this.extractParameterFields(params);
    this.smsGatewayProviderParametersFields.set(values);
  }

  private extractParameterFields(params: {
    groups: { fields: FormBuilderField[] }[];
  }): { key: string; title: string }[] {
    const values: { key: string; title: string }[] = [];

    for (const group of params.groups) {
      for (const field of group.fields) {
        // Add the main field
        values.push({
          key: field.id,
          title: field.title,
        });

        // Process combo field values if they exist
        if (field.type === 'combo' && field.values) {
          this.processComboFieldValues(field.values, values);
        }
      }
    }

    return values;
  }

  private processComboFieldValues(
    options: {
      key: string;
      value: string;
      fields?: FormBuilderField[];
    }[],
    values: { key: string; title: string }[],
  ): void {
    for (const option of options) {
      if (isDefined(option.fields)) {
        this.processOptionFields(option.fields, values);
      }
    }
  }

  private processOptionFields(
    fields: FormBuilderField[],
    values: { key: string; title: string }[],
  ): void {
    for (const subField of fields) {
      values.push({
        key: subField.id,
        title: subField.title,
      });
    }
  }

  getParametersTitle(key: string): string {
    return (
      this.smsGatewayProviderParametersFields()?.find(
        (field) => field.key === key,
      )?.title ?? ''
    );
  }
}
