import { CommonModule } from '@angular/common';
import {
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  AssetCategoryCreateRequest,
  AssetCategoryResponse,
} from '../../../../../api';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { AssetCategoryDetailsSectionComponent } from '../asset-category-details-section/asset-category-details-section.component';
import { Step } from '../../../../../shared/models';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';

@Component({
  selector: 'app-asset-category-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    AssetCategoryDetailsSectionComponent,
  ],
  templateUrl: './asset-category-create-wizard.component.html',
  styleUrl: './asset-category-create-wizard.component.scss',
})
export class AssetCategoryCreateWizardComponent
  implements AfterViewInit, OnInit
{
  @ViewChild('assetCategoryDetailsStep')
  assetCategoryDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;

  // References to form components
  @ViewChild('assetCategoryDetailsForm')
  assetCategoryDetailsForm!: AssetCategoryDetailsSectionComponent;

  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);
  private readonly cdr = inject(ChangeDetectorRef);

  // AssetCategory model to collect data across steps
  newAssetCategory = signal<AssetCategoryCreateRequest>(
    {} as AssetCategoryCreateRequest,
  );

  // Form validity state
  formIsValid = signal<boolean>(false);

  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    this.steps = [
      {
        value: 1,
        header: 'Asset Category Details',
        content: this.assetCategoryDetailsStep,
        complete: false,
        validate: () => this.assetCategoryDetailsForm.validate(),
      },
      {
        value: 2,
        header: 'Confirmation',
        content: this.confirmationTemplate,
        complete: true,
      },
    ];
    this.cdr.detectChanges();
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize assetCategory with ownerId
      this.newAssetCategory.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  openWizard() {
    this.newAssetCategory.set({} as AssetCategoryCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  // Update the assetCategory state with form data
  updateAssetCategoryDetails(formData: Record<string, unknown>) {
    this.newAssetCategory.update((current) => {
      const updated = { ...current };

      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  onWizardComplete(): void {
    // Process the final data from all steps
    const assetCategoryData = this.newAssetCategory();

    this.entitiesService
      .createAssetCategory(assetCategoryData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: AssetCategoryResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset-category',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          // Handle error, could show message and keep dialog open
          console.error('Error creating asset category:', error);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newAssetCategory.set({} as AssetCategoryCreateRequest);
    this.dialogRef.close();
  }
}
