import {
  AfterViewInit,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  DeviceProviderCreateRequest,
  DeviceProviderResponse,
  DeviceProviderTypeResponse,
} from '../../../../../api';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { DeviceProviderDetailsSectionComponent } from '../device-provider-details-section/device-provider-details-section.component';
import { Step } from '../../../../../shared/models';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { DeviceProviderParametersSectionComponent } from '../device-provider-parameters-section/device-provider-parameters-section.component';
import { RequestCacheService } from '../../../../../shared/services/request-cache.service';
import { firstValueFrom } from 'rxjs';
import { FormBuilderField } from '../../device/device-accessory-section/device-accessory-section.component';

@Component({
  selector: 'app-device-provider-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    DeviceProviderDetailsSectionComponent,
    DeviceProviderParametersSectionComponent,
  ],
  templateUrl: './device-provider-create-wizard.component.html',
  styleUrl: './device-provider-create-wizard.component.scss',
})
export class DeviceProviderCreateWizardComponent
  implements AfterViewInit, OnInit
{
  @ViewChild('deviceProviderDetailsStep')
  deviceProviderDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('deviceProviderParametersStep')
  deviceProviderParametersStep!: TemplateRef<{
    $implicit: Step;
  }>;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;

  // References to form components
  @ViewChild('deviceProviderDetailsForm')
  deviceProviderDetailsForm!: DeviceProviderDetailsSectionComponent;
  @ViewChild('deviceProviderParametersForm')
  deviceProviderParametersForm!: DeviceProviderParametersSectionComponent;
  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly cacheService = inject(RequestCacheService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);

  // DeviceProvider model to collect data across steps
  newDeviceProvider = signal<DeviceProviderCreateRequest>(
    {} as DeviceProviderCreateRequest,
  );
  readonly deviceProviderParametersFields = signal<
    { key: string; title: string }[] | null
  >(null);
  deviceProviderType = signal<DeviceProviderTypeResponse | null>(null);
  // Form validity state
  formIsValid = signal<boolean>(false);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    setTimeout(() => {
      // Only update the view-dependent properties
      this.steps[0].content = this.deviceProviderDetailsStep;
      this.steps[0].validate = () => this.deviceProviderDetailsForm.validate();

      this.steps[1].content = this.deviceProviderParametersStep;
      this.steps[1].validate = () =>
        this.deviceProviderParametersForm.validate();

      this.steps[2].content = this.confirmationTemplate;
      this.steps[2].validate = () => true;
    });
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize deviceProvider with ownerId
      this.newDeviceProvider.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }

    this.steps = [
      {
        value: 1,
        header: 'Device Provider Details',
        complete: false,
        content: null,
      },
      {
        value: 2,
        header: 'Device Provider Parameters',
        content: null,
        complete: false,
      },
      {
        value: 3,
        header: 'Confirmation',
        complete: true,
        content: null,
      },
    ];
  }

  openWizard() {
    this.displayWizard = true;
    this.newDeviceProvider.set({} as DeviceProviderCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  onParametersFormValidityChange(isValid: boolean) {
    this.steps[1].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  updateDeviceProviderDetails(formData: Record<string, unknown>) {
    this.newDeviceProvider.update((current) => {
      const { ownerId: _ownerId, ...rest } = formData;
      const updated = { ...current, ...rest };

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
    this.loadDeviceProviderType(
      this.newDeviceProvider().deviceProviderType?.id,
    ).catch(() => {});
  }

  updateDeviceProviderParameters(formData: Record<string, unknown>) {
    this.newDeviceProvider.update((current) => {
      const updated = { ...current, ...formData };
      return updated;
    });
  }

  onWizardComplete(): void {
    const deviceProviderData = this.newDeviceProvider();

    if (
      isNullOrUndefined(deviceProviderData) ||
      Object.keys(deviceProviderData).length === 0
    ) {
      return;
    }

    this.entitiesService
      .createDeviceProvider(deviceProviderData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: DeviceProviderResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'device-provider',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newDeviceProvider.set({} as DeviceProviderCreateRequest);
    this.dialogRef.close();
  }

  async loadDeviceProviderType(
    deviceProviderTypeId: string | undefined,
  ): Promise<void> {
    if (isNullOrUndefined(deviceProviderTypeId)) return;
    await this.cacheService
      .getOrFetchAsync(
        `deviceProviderType-${deviceProviderTypeId}`,
        () =>
          firstValueFrom(
            this.entitiesService.getDeviceProviderType(deviceProviderTypeId),
          ),
        300000,
      )
      .then((response) => {
        this.deviceProviderType.set(response);
        const params: { groups: { fields: FormBuilderField[] }[] } = JSON.parse(
          response.parameters,
        );
        const values: { key: string; title: string }[] = [];
        params.groups.forEach((group) => {
          group.fields.forEach((field: FormBuilderField) => {
            values.push({
              key: field.id,
              title: field.title,
            });
          });
        });
        this.deviceProviderParametersFields.set(values);
      });
  }
}
