import {
  Component,
  input,
  output,
  signal,
  computed,
  ChangeDetectionStrategy,
  ViewChild,
  ElementRef,
  OnDestroy,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { InputTextModule } from 'primeng/inputtext';
import { ButtonModule } from 'primeng/button';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { ScrollerModule } from 'primeng/scroller';
import { isNullOrUndefined } from '../../utils';
import { TreeSearchResult } from '../../models';
import { IconField } from 'primeng/iconfield';
import { InputIcon } from 'primeng/inputicon';

@Component({
  selector: 'app-tree-search',
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    InputTextModule,
    ButtonModule,
    ProgressSpinnerModule,
    ScrollerModule,
    InputIcon,
    IconField,
  ],
  templateUrl: './tree-search.component.html',
  styleUrl: './tree-search.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class TreeSearchComponent implements OnDestroy {
  @ViewChild('searchInput') searchInput!: ElementRef<HTMLInputElement>;

  // Inputs
  readonly placeholder = input<string>('Search company structure...');
  readonly disabled = input<boolean>(false);
  readonly results = input<TreeSearchResult[]>([]);
  readonly isSearching = input<boolean>(false);
  readonly maxDisplayResults = input<number>(10);

  // Outputs
  readonly queryChange = output<string>();
  readonly resultSelect = output<TreeSearchResult>();
  readonly searchClear = output<void>();

  // Internal state
  readonly searchQuery = signal<string>('');
  readonly showResults = signal<boolean>(false);
  readonly selectedIndex = signal<number>(-1);
  readonly showAll = signal<boolean>(false); // Added showAll signal

  // Computed values
  readonly hasQuery = computed(() => this.searchQuery().trim().length > 0);
  readonly hasResults = computed(() => this.results().length > 0);
  readonly displayResults = computed(() => {
    if (this.showAll()) {
      return this.results();
    }
    const maxResults = this.maxDisplayResults();
    return this.results().slice(0, maxResults);
  });
  readonly hasMoreResults = computed(
    () => !this.showAll() && this.results().length > this.maxDisplayResults(),
  );

  private readonly clickListener?: (event: Event) => void;

  constructor() {
    // Close results panel when clicking outside
    this.clickListener = (event: Event) => {
      if (
        this.showResults() &&
        isNullOrUndefined(
          this.searchInput?.nativeElement?.contains(event.target as Node),
        )
      ) {
        this.hideResults();
      }
    };
    document.addEventListener('click', this.clickListener);
  }

  ngOnDestroy(): void {
    if (this.clickListener) {
      document.removeEventListener('click', this.clickListener);
    }
  }

  onSearchInput(value: string): void {
    this.searchQuery.set(value);
    this.queryChange.emit(value);
    this.showAll.set(false); // Reset showAll on new search

    if (value.trim().length > 0) {
      this.showResults.set(true);
      this.selectedIndex.set(-1);
    } else {
      this.hideResults();
    }
  }

  onSearchKeydown(event: KeyboardEvent): void {
    const results = this.displayResults();

    switch (event.key) {
      case 'ArrowDown':
        event.preventDefault();
        this.selectedIndex.update((index) =>
          Math.min(index + 1, results.length - 1),
        );
        break;

      case 'ArrowUp':
        event.preventDefault();
        this.selectedIndex.update((index) => Math.max(index - 1, -1));
        break;

      case 'Enter': {
        event.preventDefault();
        const selectedIdx = this.selectedIndex();

        // If an item is selected, use it; otherwise, select the first result if available
        if (selectedIdx >= 0 && selectedIdx < results.length) {
          this.selectResult(results[selectedIdx]);
        } else if (results.length > 0) {
          // Default action: select the first result when no item is selected
          this.selectResult(results[0]);
        }
        break;
      }

      case 'Escape':
        event.preventDefault();
        this.clearSearch();
        break;
    }
  }

  selectResult(result: TreeSearchResult): void {
    this.resultSelect.emit(result);
    this.hideResults();
    this.searchInput.nativeElement.blur();
  }

  clearSearch(): void {
    this.searchQuery.set('');
    this.hideResults();
    this.searchClear.emit();
    this.searchInput.nativeElement.focus();
  }

  private hideResults(): void {
    this.showResults.set(false);
    this.selectedIndex.set(-1);
    this.showAll.set(false); // Reset showAll when hiding results
  }

  onInputFocus(): void {
    if (this.hasQuery() && this.hasResults()) {
      this.showResults.set(true);
    }
  }

  getResultTypeIcon(type: string): string {
    switch (type) {
      case 'client':
        return 'pi pi-user';
      case 'vendor':
        return 'pi pi-building';
      case 'group':
        return 'pi pi-users';
      case 'distributor':
        return 'pi pi-globe';
      default:
        return 'pi pi-circle';
    }
  }

  getResultTypeLabel(type: string): string {
    switch (type) {
      case 'client':
        return 'Client';
      case 'vendor':
        return 'Vendor';
      case 'group':
        return 'Group';
      case 'distributor':
        return 'Distributor';
      default:
        return type;
    }
  }

  formatPath(path: string[]): string {
    if (isNullOrUndefined(path) || path.length === 0) {
      return '';
    }
    return path.slice(0, -1).join(' > ');
  }

  showAllResults(): void {
    this.showAll.set(true);
  }
}
