@Component({
  selector: 'app-admin-container',
  imports: [
    AdaptiveLayoutComponent,
    RouterModule,
    TreePanelComponent,
    ToolbarModule,
    ButtonModule,
    InputTextModule,
    CommonModule,
    ProgressSpinnerModule,
    DetailsPanelComponent,
    FontAwesomeModule,
    TreeSearchComponent,
  ],
  templateUrl: './admin-container.component.html',
  styleUrl: './admin-container.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})

/*
 * Admin Container Layout
 *
 * This component uses a PrimeNG p-splitter for resizable panels.
 * The layout adapts between showing/hiding detail panels based on state.
 */
export class AdminContainerComponent implements OnInit {
  private readonly adminState = inject(AdminStateService);
  private readonly adminDataService = inject(AdminDataService);
  private readonly messageService = inject(MessageService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly adminTreeService = inject(AdminTreeService);
  private readonly cdr = inject(ChangeDetectorRef);
  private readonly router = inject(Router);
  private readonly activatedRoute = inject(ActivatedRoute);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  readonly detailsService = inject(EntityDetailsService);
  private readonly adminSearchService = inject(AdminSearchService);

  private readonly destroyRef = inject(DestroyRef);

  readonly isLoading = this.adminState.isLoading;
  readonly selectedItem = signal<unknown>(null);
  readonly detailsComponent = signal<Type<unknown> | null>(null);
  readonly detailsInputs = signal<Record<string, unknown>>({});
  readonly hasMoreData = signal<boolean>(false);
  readonly loadingMore = signal<boolean>(false);
  selectedTreeNode = signal<TreeNode | null>(null);

  // Search-related computed values
  readonly searchResults = this.adminSearchService.results;
  readonly isSearching = this.adminSearchService.isSearching;
  readonly hasSearchQuery = this.adminSearchService.hasQuery;

  /**
   * Computed property that builds the hierarchy tree including "Load More" nodes.
   * Now enhanced with search highlighting and expansion.
   */
  readonly hierarchyTree = computed(() => {
    const distributor = this.adminState.vendorDistributor();
    const vendor = this.adminState.clientVendor();
    const selectedClient = this.adminState.selectedClient();

    // Get search state for tree modifications
    const searchExpandedNodes = this.adminSearchService.expandedForSearch();

    // If distributor exists, build the full hierarchy
    if (distributor) {
      const tree = this.buildDistributorHierarchy(distributor, selectedClient);
      return this.applySearchEnhancements(tree, searchExpandedNodes);
    }
    // If only vendor exists (no distributor or fallback)
    else if (vendor) {
      const tree = this.buildVendorOnlyHierarchy(vendor, selectedClient);
      return this.applySearchEnhancements(tree, searchExpandedNodes);
    }
    // Fallback to just the client if no vendor/distributor context (should be rare)
    else if (selectedClient) {
      return [this.adminTreeService.createClientNode(selectedClient, true)];
    }

    return []; // No data yet or error state
  });

  activeGridComponent: unknown;
  readonly detailsLoading = signal<boolean>(false);

  /**
   * Returns the CSS class for the main container based on details panel state
   */
  readonly hostClass = computed(() => {
    return this.detailsService.showPanel() ? 'has-details' : '';
  });

  /**
   * Returns the CSS class for the main splitter
   */
  readonly mainSplitterClass = computed(() => {
    return 'main-layout';
  });

  /**
   * Returns the CSS class for the details panel based on its visibility
   */
  readonly detailsPanelClass = computed(() => {
    return this.detailsService.showPanel()
      ? 'details-visible-state'
      : 'details-hidden-state';
  });

  /**
   * Signal to determine if the nested router outlet content should be scrollable.
   * Defaults to false (for grid pages).
   */
  protected nestedContentScrollable = signal<boolean>(false);

  private readonly localStorage = inject(LocalStorageService);
  faAngleLeft = faAngleLeft;
  faAngleRight = faAngleRight;

  // Collapsible tree state
  readonly treeCollapsed = signal<boolean>(true);

  // Only show tree if user has access to more than one client
  readonly showTreePanel = computed(() => {
    // Check if there are multiple clients in any vendor
    const vendorClients = this.adminState.vendorClients();
    return Object.keys(vendorClients).some((vendorId) => {
      const clients = vendorClients[vendorId];
      return Array.isArray(clients) && clients.length > 1;
    });
  });

  toggleTreePanel() {
    const newState = !this.treeCollapsed();
    this.treeCollapsed.set(newState);
    this.localStorage.setItem('admin-tree-collapsed', newState);
  }

  constructor() {
    effect(() => {
      const currentSelectedClient = this.adminState.selectedClient();
      const currentTreeNode = this.selectedTreeNode();
      // This effect syncs tree selection if adminState.selectedClient() changes from other sources.
      // Route-driven selection is handled by selectNodeFromRouteOrState.
      if (
        currentSelectedClient &&
        (currentTreeNode?.key !== currentSelectedClient.id ||
          currentTreeNode?.data?.type !== ADMIN_TREE.NODE_TYPES.CLIENT)
      ) {
        const treeNodes = this.hierarchyTree();
        if (treeNodes.length > 0) {
          const nodeToSelect = this.findNodeRecursively(
            treeNodes,
            currentSelectedClient.id,
            ADMIN_TREE.NODE_TYPES.CLIENT,
          );
          this.selectedTreeNode.set(nodeToSelect);
          if (nodeToSelect) {
            this.adminDataService.selectNode(nodeToSelect); // Update global state
          }
        }
      }
    });
  }

  ngOnInit(): void {
    const selectedClient = this.clientDataService.getSelectedClient();
    const firstChildSnapshot = this.activatedRoute.firstChild?.snapshot;
    const firstChildPath = firstChildSnapshot?.url[0]?.path;

    if (
      isDefined(selectedClient) &&
      hasProperty(selectedClient, 'id') &&
      isString(selectedClient.id) &&
      !isDefined(firstChildPath)
    ) {
      this.router
        .navigate(['/admin', 'client', selectedClient.id])
        .catch((err) =>
          console.error('Failed to navigate to default client:', err),
        );
    }

    // Get the client ID from the route if available
    const { keyToSelect, typeToSelect } = this.getEntityInfoFromRoute();
    const routeClientId =
      typeToSelect === ADMIN_TREE.NODE_TYPES.CLIENT && isDefined(keyToSelect)
        ? keyToSelect
        : undefined;

    this.adminDataService
      .loadInitialData(routeClientId)
      .then(() => {
        this.selectNodeFromRouteOrState();
        // Add tree selection synchronization after initial load
        this.syncTreeSelectionWithRouteAndLocalStorage().catch((err) =>
          console.error('Error syncing tree selection:', err),
        );
        this.cdr.detectChanges();
      })
      .catch(() => {
        // Even on error, try to restore selection if possible (e.g. from route)
        this.selectNodeFromRouteOrState();
        this.syncTreeSelectionWithRouteAndLocalStorage().catch((err) =>
          console.error('Error syncing tree selection:', err),
        );
        this.cdr.detectChanges();
      });

    this.router.events
      .pipe(
        filter(
          (event): event is NavigationEnd => event instanceof NavigationEnd,
        ),
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe(() => {
        const currentQueryParams = this.activatedRoute.snapshot.queryParams;
        const hasDetailsParams =
          isDefined(currentQueryParams['details']) &&
          isDefined(currentQueryParams['type']);

        if (this.detailsService.showPanel() && !hasDetailsParams) {
          const item = this.detailsService.selectedItem();
          if (
            isDefined(item) &&
            hasProperty(item, 'id') &&
            hasProperty(item, 'type')
          ) {
            const baseUrl = this.router.url.split('?')[0];
            this.router
              .navigate([baseUrl], {
                queryParams: { details: item['id'], type: item['type'] ?? '' },
                queryParamsHandling: 'merge',
                replaceUrl: true,
              })
              .catch(() => {});
          }
        }
        // After any navigation, try to sync tree selection with the route
        this.selectNodeFromRouteOrState();
      });

    // Function to get scrollable state from route
    const getScrollableState = (route: ActivatedRoute): boolean => {
      let currentRoute = route;
      while (currentRoute.firstChild) {
        currentRoute = currentRoute.firstChild;
      }
      const routeData: Data = currentRoute.snapshot.data;
      if (
        isDefined(routeData) &&
        typeof routeData['nestedContentScrollable'] === 'boolean'
      ) {
        return routeData['nestedContentScrollable'];
      }
      return false; // Default to false
    };

    // Set initial state
    this.nestedContentScrollable.set(getScrollableState(this.activatedRoute));
    this.cdr.detectChanges(); // Ensure initial class binding is applied

    // Subscribe to subsequent navigation events
    this.router.events
      .pipe(
        filter(
          (event): event is NavigationEnd => event instanceof NavigationEnd,
        ),
        map(() => getScrollableState(this.activatedRoute)), // Reuse the logic
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe((scrollableValue: boolean) => {
        if (this.nestedContentScrollable() !== scrollableValue) {
          this.nestedContentScrollable.set(scrollableValue);
          this.cdr.detectChanges(); // Explicitly trigger change detection if needed
        }
      });

    this.broadcastService
      .on('view-entity-in-tree')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((data) => {
        const item = data?.entity;
        // Check for a client entity from the details panel
        if (isDefined(item?.id) && item.entityType === 'client') {
          this.handleClientInTree(
            item as ClientListItem,
            item['vendorId'] as string,
            item['groupId'] as string | undefined,
          ).catch((err) => this.handleError(err, 'Error showing item in tree'));
        }

        if (isDefined(item?.id) && item.entityType === 'vendor') {
          this.handleVendorInTree(item as VendorListItem).catch((err) =>
            this.handleError(err, 'Error showing vendor in tree'),
          );
        }
      });

    // Handle entity updates to refresh tree state
    this.broadcastService
      .on('entity-updated')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((data: unknown) => {
        if (
          isDefined(data) &&
          typeof data === 'object' &&
          data !== null &&
          'entityType' in data &&
          'operation' in data &&
          'entityId' in data
        ) {
          const updateData = data as {
            entityType: string;
            operation: string;
            entityId: string;
          };

          // Handle client creation
          if (
            updateData.entityType === 'client' &&
            updateData.operation === 'create' &&
            updateData.entityId
          ) {
            this.handleClientCreated(updateData.entityId).catch((err) =>
              this.handleError(
                err,
                'Error refreshing tree after client creation',
              ),
            );
          }
        }
      });
  }

  /**
   * Handles the 'view-entity-in-tree' event for a client by delegating to the search service.
   * @param client The client entity to show.
   * @param vendorId The ID of the parent vendor.
   * @param groupId The optional ID of the parent group.
   */
  private async handleClientInTree(
    client: ClientListItem,
    vendorId: string,
    groupId?: string,
  ): Promise<void> {
    try {
      this.detailsService.closeDetailsPanel();

      // Ensure the tree panel is open
      if (this.treeCollapsed()) {
        this.toggleTreePanel();
      }

      // Delegate to the search service
      const result = await this.adminSearchService.handleClientInTree(
        client,
        vendorId,
        groupId,
      );

      // Allow the UI time to update with the newly expanded nodes
      this.cdr.detectChanges();
      await new Promise((resolve) => setTimeout(resolve, 100));

      // Navigate to the node and update UI
      await this.navigateToSearchResult(result);
    } catch (err) {
      this.handleError(err, 'Error showing item in tree');
    }
  }

  /**
   * Handles the 'view-entity-in-tree' event for a vendor by delegating to the search service.
   * @param vendor The vendor entity to show.
   */
  private async handleVendorInTree(vendor: VendorListItem): Promise<void> {
    try {
      this.detailsService.closeDetailsPanel();

      // Ensure the tree panel is open
      if (this.treeCollapsed()) {
        this.toggleTreePanel();
      }

      // Delegate to the search service
      const result = await this.adminSearchService.handleVendorInTree(vendor);

      // Allow the UI time to update with the newly expanded nodes
      this.cdr.detectChanges();
      await new Promise((resolve) => setTimeout(resolve, 100));

      // Navigate to the node and update UI
      await this.navigateToSearchResult(result);
    } catch (err) {
      this.handleError(err, 'Error showing vendor in tree');
    }
  }

  /**
   * Common method to navigate to a search result and update the tree selection.
   * @param result The search result to navigate to.
   */
  private async navigateToSearchResult(
    result: TreeSearchResult,
  ): Promise<void> {
    // Navigate to the node, which will also cause the grid to update
    await this.navigateToNode(result.type, result.id);

    // As a final step, explicitly find and set the selected node in the tree
    const finalTree = this.hierarchyTree();
    const nodeToSelect = this.findNodeByKeyRecursive(finalTree, result.id);

    if (nodeToSelect) {
      this.selectedTreeNode.set(nodeToSelect);
    }
    this.cdr.detectChanges();
  }

  /**
   * Finds a node in the hierarchy recursively by key and type.
   */
  private findNodeRecursively(
    nodes: TreeNode[],
    key: string,
    type?: string,
  ): TreeNode | null {
    for (const node of nodes) {
      if (node.key === key && (isNullOrUndefined(type) || node.type === type)) {
        return node;
      }
      if (node.children) {
        const found = this.findNodeByKeyRecursive(node.children, key);
        if (found) {
          return found;
        }
      }
    }
    return null;
  }

  // --- Tree Building Logic with Pagination ---

  private buildDistributorHierarchy(
    distributor: DistributorResponse,
    selectedClient: ClientResponse | null,
  ): TreeNode[] {
    const allVendors = this.adminState.vendors(); // List of vendors under the distributor
    const expandedDistributors = this.adminState.expandedDistributors();
    const isDistributorExpanded = expandedDistributors.has(distributor.id);

    const distributorNode = this.adminTreeService.createDistributorNode(
      distributor,
      isDistributorExpanded,
    );

    if (isDistributorExpanded) {
      distributorNode.children = allVendors.map((vendor) =>
        this.buildVendorNode(vendor, selectedClient),
      );
      // Potentially add a "Load More Vendors" node here if distributors can have many vendors with pagination
    } else {
      distributorNode.children = [];
    }

    return [distributorNode];
  }

  private buildVendorOnlyHierarchy(
    vendor: VendorResponse | VendorListItem,
    selectedClient: ClientResponse | null,
  ): TreeNode[] {
    const vendorNode = this.buildVendorNode(vendor, selectedClient);
    return [vendorNode];
  }

  private buildVendorNode(
    vendor: VendorResponse | VendorListItem,
    selectedClient: ClientResponse | null,
  ): TreeNode {
    const vendorClientsMap = this.adminState.vendorClients();
    const vendorGroupsMap = this.adminState.vendorGroups();
    const groupClientsMap = this.adminState.groupClients();
    const expandedNodes = this.adminState.expandedNodes();
    const expandedGroups = this.adminState.expandedGroups();
    const paginationState = this.adminState.clientPagination();

    const isVendorExpanded = expandedNodes.has(vendor.id);
    const vendorNode = this.adminTreeService.createVendorNode(
      vendor,
      isVendorExpanded,
      [],
      selectedClient?.id === vendor.id,
    );

    if (isVendorExpanded) {
      const groups = vendorGroupsMap[vendor.id] ?? [];
      const directClients = vendorClientsMap[vendor.id] ?? [];
      const vendorPaginationKey = vendor.id;
      const vendorPagination = paginationState[vendorPaginationKey];

      vendorNode.children = [
        // Groups first
        ...groups.map((group) => {
          const isGroupExpanded = expandedGroups.has(group.id);
          const groupNode = this.adminTreeService.createGroupNode(
            group,
            isGroupExpanded,
            [], // Placeholder for children, will be filled later
            selectedClient?.id === group.id,
          );
          const groupPaginationKey = `${vendor.id}_${group.id}`;
          const groupPagination = paginationState[groupPaginationKey];

          if (isGroupExpanded) {
            const clientsInGroup = groupClientsMap[vendor.id]?.[group.id] ?? [];
            groupNode.children = clientsInGroup.map((client) =>
              this.adminTreeService.createClientNode(
                client,
                selectedClient?.id === client.id,
              ),
            );

            // Add "Load More" for the group
            if (groupPagination?.hasMore === true) {
              groupNode.children.push(
                this.createLoadMoreNode(
                  vendor.id,
                  group.id,
                  groupPagination.loadingMore,
                ),
              );
            }
          } else {
            groupNode.children = [];
          }
          return groupNode;
        }),
        // Direct clients next
        ...directClients.map((client) =>
          this.adminTreeService.createClientNode(
            client,
            selectedClient?.id === client.id,
          ),
        ),
      ];

      if (vendorPagination?.hasMore === true) {
        vendorNode.children.push(
          this.createLoadMoreNode(
            vendor.id,
            undefined,
            vendorPagination.loadingMore,
          ),
        );
      }
    } else {
      vendorNode.children = [];
    }

    return vendorNode;
  }

  private createLoadMoreNode(
    vendorId: string,
    groupId: string | undefined,
    loading: boolean,
  ): TreeNode {
    const key = `loadmore_${vendorId}${isDefined(groupId) ? '_' + groupId : ''}`;
    return {
      key: key,
      label: 'Load More...',
      type: ADMIN_TREE.NODE_TYPES.LOAD_MORE,
      leaf: true,
      icon: loading ? 'pi pi-spin pi-spinner' : 'pi pi-plus',
      data: {
        type: ADMIN_TREE.NODE_TYPES.LOAD_MORE,
        vendorId: vendorId,
        groupId: groupId,
        loading: loading,
      },
      styleClass: 'load-more-node',
    };
  }

  private async navigateToNode(
    nodeType: string,
    nodeKey: string,
  ): Promise<boolean> {
    let entityType = '';
    const entityId = nodeKey;

    switch (nodeType) {
      case ADMIN_TREE.NODE_TYPES.CLIENT:
        entityType = 'client';
        break;
      case ADMIN_TREE.NODE_TYPES.VENDOR:
        entityType = 'vendor';
        break;
      case ADMIN_TREE.NODE_TYPES.GROUP:
        // Decide if navigating to a group view is needed, or just select
        // For now, assume we navigate to the parent vendor if a group is clicked
        // Or potentially clear details / show group info if available
        return Promise.resolve(false); // Prevent navigation for now
      // entityType = 'group'; // If group has its own route/view

      case ADMIN_TREE.NODE_TYPES.DISTRIBUTOR:
        entityType = 'distributor';
        break;
      default:
        console.warn('Unknown node type for navigation:', nodeType);
        return Promise.resolve(false);
    }

    if (entityType && entityId) {
      this.broadcastService.broadcast('entity-changed', {
        entityType: nodeType,
        entityId: nodeKey,
      });
      return this.handleEntityNavigation(entityType, entityId);
    }
    return Promise.resolve(false);
  }

  private handleEntityNavigation(
    entityType: string,
    entityId: string,
  ): Promise<boolean> {
    const currentRoute = this.activatedRoute.firstChild?.snapshot;
    const currentEntityType = currentRoute?.url[0]?.path;
    const currentEntityIdParamName = isDefined(currentEntityType)
      ? `${currentEntityType}Id`
      : 'id';
    const currentEntityId =
      currentRoute?.params[currentEntityIdParamName] ??
      currentRoute?.params['id'];

    // Avoid redundant navigation if already on the exact same entity route
    if (currentEntityType === entityType && currentEntityId === entityId) {
      // If we are already on the correct entity, check if sub-routes (tabs) are present.
      // If the URL is just /admin/entityType/entityId without any tabs,
      // and the intent was to navigate to a default tab, that logic would be separate.
      // For now, if base entity is same, consider it a success.
      return Promise.resolve(true);
    }

    const urlSegments = this.router.url.split('?')[0].split('/');
    let tabPath = '';

    // Try to find existing tab path if navigating within the same entity type
    // Example: /admin/client/123/settings -> entityType='client', entityId='456'
    // We want to preserve '/settings' if currentEntityType is also 'client'
    if (currentEntityType === entityType) {
      const entityTypeIndexInUrl = urlSegments.findIndex(
        (segment) => segment === currentEntityType,
      );
      if (
        entityTypeIndexInUrl > -1 &&
        urlSegments.length > entityTypeIndexInUrl + 2
      ) {
        // +1 is ID, +2 onwards is tab path
        tabPath = urlSegments.slice(entityTypeIndexInUrl + 2).join('/');
      }
    }

    const navigationTarget: (string | undefined)[] = [
      '/admin',
      entityType,
      entityId,
    ];
    if (tabPath) {
      navigationTarget.push(...tabPath.split('/'));
    }

    return this.router.navigate(navigationTarget.filter(isDefined));
  }

  private handleError(error: unknown, message: string): void {
    console.error(message, error);
    this.messageService.add({
      severity: 'error',
      summary: 'Error',
      detail: `${message}: ${error instanceof Error ? error.message : 'Unknown error'}`,
    });
  }

  /** Recursive helper to find TreeNode by key */
  private findNodeByKeyRecursive(
    nodes: TreeNode[],
    key: string,
  ): TreeNode | null {
    for (const node of nodes) {
      if (node.key === key) {
        return node;
      }
      if (node.children) {
        const found = this.findNodeByKeyRecursive(node.children, key);
        if (found) return found;
      }
    }
    return null;
  }

  /**
   * Handles node expansion
   */
  async onNodeExpand(node: TreeNode): Promise<void> {
    try {
      // Use specific expand methods from data service regardless of previous state
      switch (node.type) {
        case ADMIN_TREE.NODE_TYPES.VENDOR:
          // Force reload by removing from loaded vendors if necessary
          if (isDefined(node.data?.id)) {
            const vendorId = node.data.id;
            // Only force reload if the children array is empty but should have data
            if (
              !(node.children?.length ?? 0) &&
              this.adminState.loadedVendors().has(vendorId)
            ) {
              this.adminState.removeFromLoadedVendors(vendorId);
            }
          }
          await this.adminDataService.expandNode(node);
          break;
        case ADMIN_TREE.NODE_TYPES.GROUP:
          // Similarly, we may need to clear pagination state to force reload
          if (isDefined(node.data?.id) && isDefined(node?.parent?.data?.id)) {
            const groupId = node.data.id;
            const vendorId = node?.parent?.data.id;
            const paginationKey = `${vendorId}_${groupId}`;
            // Clear pagination if children array is empty
            if (
              !(node.children?.length ?? 0) &&
              isDefined(this.adminState.clientPagination()[paginationKey])
            ) {
              this.adminState.clearGroupPagination(vendorId, groupId);
            }
          }
          await this.adminDataService.expandGroup(node);
          break;
        case ADMIN_TREE.NODE_TYPES.DISTRIBUTOR:
          this.adminDataService.expandDistributor(node);
          break;
      }
      this.cdr.detectChanges();
    } catch (error: unknown) {
      this.handleError(error, 'Failed to expand node');
    }
  }

  async onGroupExpand(groupNode: TreeNode): Promise<void> {
    await this.adminDataService.expandGroup(groupNode);
  }

  onNodeCollapse(node: TreeNode): void {
    if (isNullOrUndefined(node.data?.id)) return;
    switch (node.type) {
      case ADMIN_TREE.NODE_TYPES.VENDOR:
        this.adminDataService.collapseNode(node);
        break;
      case ADMIN_TREE.NODE_TYPES.GROUP:
        this.adminDataService.collapseGroup(node);
        break;
      case ADMIN_TREE.NODE_TYPES.DISTRIBUTOR:
        this.adminDataService.collapseDistributor(node);
        break;
    }
    this.cdr.detectChanges();
  }

  async onNodeSelect(node: TreeNode): Promise<void> {
    this.selectedTreeNode.set(node);

    if (node.type === ADMIN_TREE.NODE_TYPES.LOAD_MORE) {
      const loadData = node.data as {
        vendorId: string;
        groupId?: string;
        loading?: boolean;
      };
      if (isDefined(loadData.vendorId)) {
        await this.adminDataService.loadMoreClients(
          loadData.vendorId,
          loadData.groupId,
        );
        this.cdr.detectChanges();
      }
    } else if (isDefined(node.key) && isDefined(node.type)) {
      this.adminDataService.selectNode(node);
      await this.navigateToNode(node.type, node.key);
    }
  }

  onNodeUnselect(node: TreeNode): void {
    if (this.selectedTreeNode()?.key === node.key) {
      this.selectedTreeNode.set(null);
      this.adminState.setSelectedClient(null); // Clear selected client in the state
    }
  }

  findSelectedNode(): TreeNode | null {
    // First check the selectedTreeNode from internal state
    const selectedNode = this.selectedTreeNode();
    if (selectedNode) return selectedNode;

    // Fallback to client-based selection if no direct node selection
    const selectedClient = this.adminState.selectedClient();
    if (!selectedClient) return null;

    const nodes = this.hierarchyTree();
    return this.adminDataService.findSelectedNode(nodes, selectedClient.id);
  }

  // Capture the activated router outlet component
  onRouterOutletActivate(component: unknown): void {
    this.activeGridComponent = component;
  }

  /**
   * Gets entity information from route parameters
   */
  private getEntityInfoFromRoute(): {
    keyToSelect: string | null;
    typeToSelect: string | null;
  } {
    const routeSnapshot = this.activatedRoute.firstChild?.snapshot;
    let keyToSelect: string | null = null;
    let typeToSelect: string | null = null;

    if (isDefined(routeSnapshot?.url) && routeSnapshot.url.length > 0) {
      const entityTypePath = routeSnapshot.url[0]?.path; // e.g., 'client', 'vendor'

      if (entityTypePath) {
        const entityId =
          routeSnapshot.params[`${entityTypePath}Id`] ??
          routeSnapshot.params['id'];

        typeToSelect = this.getEntityTypeFromPath(entityTypePath);

        if (isDefined(entityId) && isDefined(typeToSelect)) {
          keyToSelect = entityId;
        }
      }
    }

    return { keyToSelect, typeToSelect };
  }

  /**
   * Maps URL path to entity type
   */
  private getEntityTypeFromPath(path: string): string | null {
    switch (path) {
      case ADMIN_TREE.NODE_TYPES.CLIENT:
      case 'client':
        return ADMIN_TREE.NODE_TYPES.CLIENT;
      case ADMIN_TREE.NODE_TYPES.VENDOR:
      case 'vendor':
        return ADMIN_TREE.NODE_TYPES.VENDOR;
      case ADMIN_TREE.NODE_TYPES.DISTRIBUTOR:
      case 'distributor':
        return ADMIN_TREE.NODE_TYPES.DISTRIBUTOR;
      case ADMIN_TREE.NODE_TYPES.GROUP:
      case 'group':
        return ADMIN_TREE.NODE_TYPES.GROUP;
      default:
        return null;
    }
  }

  /**
   * Selects a node in the tree based on the current route parameters.
   * This method updates the `selectedTreeNode` signal.
   */
  private selectNodeFromRouteOrState(): void {
    const { keyToSelect, typeToSelect } = this.getEntityInfoFromRoute();
    const treeNodes = this.hierarchyTree();

    this.updateSelectedNode(keyToSelect, typeToSelect, treeNodes);
    this.cdr.detectChanges();
  }

  /**
   * Updates the selected node based on provided key and type
   */
  private updateSelectedNode(
    keyToSelect: string | null,
    typeToSelect: string | null,
    treeNodes: TreeNode[],
  ): void {
    // Clear selection if no key or type
    if (isNullOrUndefined(keyToSelect) && isNullOrUndefined(typeToSelect)) {
      this.selectedTreeNode.set(null);
      return;
    }

    if (!isDefined(keyToSelect) || treeNodes.length === 0) {
      return;
    }

    // Find the node to select
    const nodeToSelect = this.findNodeToSelect(
      treeNodes,
      keyToSelect,
      typeToSelect,
    );

    if (nodeToSelect) {
      this.selectedTreeNode.set(nodeToSelect);
      this.adminDataService.selectNode(nodeToSelect);
    }
  }

  /**
   * Finds the correct node to select based on key and optional type
   */
  private findNodeToSelect(
    treeNodes: TreeNode[],
    key: string,
    type: string | null,
  ): TreeNode | null {
    // If we have a type, try to find by both key and type first
    if (isDefined(type)) {
      const nodeByType = this.findNodeByTypeAndKey(treeNodes, key, type);
      if (nodeByType) return nodeByType;
    }

    // Fall back to just finding by key
    return this.findNodeByKeyRecursive(treeNodes, key);
  }

  /**
   * Finds a node in the hierarchy by both key and type.
   * This is a helper method to avoid code duplication.
   */
  private findNodeByTypeAndKey(
    nodes: TreeNode[],
    key: string,
    type: string,
  ): TreeNode | null {
    for (const node of nodes) {
      if (node.key === key && node.type === type) {
        return node;
      }
      if (node.children) {
        const found = this.findNodeByTypeAndKey(node.children, key, type);
        if (found) return found;
      }
    }
    return null;
  }

  /**
   * Applies search enhancements to the tree structure
   */
  private applySearchEnhancements(
    nodes: TreeNode[],
    searchExpandedNodes: Set<string>,
  ): TreeNode[] {
    return nodes.map((node) =>
      this.enhanceNodeForSearch(node, searchExpandedNodes),
    );
  }

  /**
   * Enhances a single node and its children for search functionality
   */
  private enhanceNodeForSearch(
    node: TreeNode,
    searchExpandedNodes: Set<string>,
  ): TreeNode {
    const enhanced = { ...node };

    // Apply search highlighting
    if (this.adminSearchService.isNodeHighlighted(node.key as string)) {
      enhanced.styleClass = [enhanced.styleClass, 'search-highlighted']
        .filter(Boolean)
        .join(' ');
    }

    // Force expansion if required by search
    if (searchExpandedNodes.has(node.key as string)) {
      enhanced.expanded = true;
    }

    // Recursively enhance children
    if (enhanced.children) {
      enhanced.children = enhanced.children.map((child) =>
        this.enhanceNodeForSearch(child, searchExpandedNodes),
      );
    }

    return enhanced;
  }

  /**
   * Handles search query changes
   */
  onSearchQueryChange(query: string): void {
    this.adminSearchService.updateQuery(query);
  }

  /**
   * Handles search result selection
   */
  async onSearchResultSelect(result: TreeSearchResult): Promise<void> {
    try {
      // First, ensure parent nodes are loaded and expanded
      await this.adminSearchService.prepareResultForNavigation(result);

      // Wait a bit for state to update
      await new Promise((resolve) => setTimeout(resolve, 100));

      // Use the common navigation method
      await this.navigateToSearchResult(result);
    } catch (error) {
      this.handleError(error, 'Failed to navigate to search result');
    }
  }

  /**
   * Handles search clear
   */
  onSearchClear(): void {
    this.adminSearchService.clearSearch();
    this.cdr.detectChanges();
  }

  /**
   * Synchronizes tree selection between route-based client and local storage client.
   * This resolves issues where the tree highlights the wrong client after page refresh
   * when the route client is from a different hierarchy than the local storage client.
   */
  private async syncTreeSelectionWithRouteAndLocalStorage(): Promise<void> {
    try {
      // Get the current route-based client (the "correct" one)
      const currentClient = this.adminState.selectedClient();

      // Get the client from local storage for comparison
      const storedClient = this.localStorage.getItem<Partial<ClientResponse>>(
        LOCAL_STORAGE_KEY_SELECTED_CLIENT,
      );

      // If current route client is different from stored client, prioritize route client
      if (
        isDefined(currentClient?.id) &&
        (!storedClient || currentClient.id !== storedClient.id)
      ) {
        // Use the search service to prepare the client for tree selection
        const searchResult =
          await this.adminSearchService.prepareClientForTreeSelection(
            currentClient.id,
          );

        if (searchResult) {
          // Now find and select the proper node from the fully loaded tree
          const treeNodes = this.hierarchyTree();
          const nodeToSelect = this.findNodeByKeyRecursive(
            treeNodes,
            currentClient.id,
          );

          if (nodeToSelect) {
            this.selectedTreeNode.set(nodeToSelect);
            this.adminDataService.selectNode(nodeToSelect);

            // Update local storage to match the route (keeps them in sync for future)
            this.clientDataService.setSelectedClient(currentClient);
          } else {
            console.warn(
              'Could not find tree node for client after loading hierarchy',
            );
          }
        } else {
          console.warn('Could not prepare client for tree selection');
        }
      }
    } catch (error) {
      console.error('Error syncing tree selection:', error);
    }
  }

  /**
   * Handles client creation event to refresh the tree state.
   * This method delegates to the AdminDataService and handles UI updates.
   */
  private async handleClientCreated(clientId: string): Promise<void> {
    try {
      // Delegate the main logic to the service
      const client = await this.adminDataService.handleClientCreated(clientId);

      if (!client) {
        return;
      }

      // Ensure the tree panel is open to show the new client
      if (this.treeCollapsed()) {
        this.toggleTreePanel();
      }

      // Force tree refresh by triggering change detection
      this.cdr.detectChanges();

      // Wait a bit for the tree to render, then try to select the new client
      setTimeout(() => {
        const treeNodes = this.hierarchyTree();
        const newClientNode = this.findNodeRecursively(
          treeNodes,
          clientId,
          ADMIN_TREE.NODE_TYPES.CLIENT,
        );

        if (newClientNode) {
          this.selectedTreeNode.set(newClientNode);
          this.adminDataService.selectNode(newClientNode);
          this.cdr.detectChanges();
        }
      }, 100);
    } catch (error) {
      this.handleError(error, 'Error refreshing tree after client creation');
    }
  }
}
