import { inject, Injectable } from '@angular/core';
import { firstValueFrom, catchError, of, map } from 'rxjs';
import {
  AccountsService,
  VendorResponse,
  VendorListItem,
  DistributorResponse,
} from '../../../api';

/**
 * Service responsible for managing vendor-related operations in the admin tree.
 * Handles fetching vendor data, distributor relationships, and vendor lists.
 */
@Injectable({
  providedIn: 'root',
})
export class AdminTreeVendorService {
  private readonly accountsService = inject(AccountsService);

  /**
   * Fetches a vendor associated with a client
   * @param vendorId - The ID of the vendor to fetch
   * @returns Promise resolving to VendorResponse or null if not found
   * @throws Error if vendorId is empty or undefined
   */
  async fetchClientVendor(vendorId: string): Promise<VendorResponse | null> {
    if (!vendorId?.trim()) {
      throw new Error('Vendor ID is required');
    }

    return firstValueFrom(
      this.accountsService.getVendor(vendorId).pipe(
        catchError(() => {
          return of(null);
        }),
      ),
    );
  }

  /**
   * Fetches a distributor associated with a vendor
   * @param distributorId - The ID of the distributor to fetch
   * @returns Promise resolving to VendorResponse or null if not found
   * @throws Error if distributorId is empty or undefined
   */
  async fetchVendorDistributor(
    distributorId: string,
  ): Promise<DistributorResponse | null> {
    if (!distributorId?.trim()) {
      throw new Error('Distributor ID is required');
    }

    return firstValueFrom(
      this.accountsService.getDistributor(distributorId).pipe(
        catchError(() => {
          return of(null);
        }),
      ),
    );
  }

  /**
   * Lists all vendors associated with a distributor
   * @param distributorId - The ID of the distributor to fetch vendors for
   * @returns Promise resolving to array of VendorListItem
   * @throws Error if distributorId is empty or undefined
   */
  async listDistributorVendors(
    distributorId: string,
  ): Promise<VendorListItem[]> {
    if (!distributorId?.trim()) {
      throw new Error('Distributor ID is required');
    }

    return firstValueFrom(
      this.accountsService.listVendors(distributorId).pipe(
        map((response) => response.items ?? []),
        catchError(() => {
          return of([]);
        }),
      ),
    );
  }
}
