import {
  DestroyRef,
  Injectable,
  computed,
  inject,
  signal,
} from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';
import { DialogService, DynamicDialogRef } from 'primeng/dynamicdialog';
import { catchError, combineLatest, EMPTY } from 'rxjs';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import {
  GridConfiguration,
  GridDataService,
  DataGridParams,
  GridColumn,
  FilterCriteria,
  FilterValue,
  DATE_FORMATS,
} from '../../../shared/models';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import { isDefined } from '../../../shared/utils';
import { AssetsDataAdapter } from '../services/adapters';
import { AssetListItem, EntitiesService } from '../../../api';
import { DEFAULT_PAGE_SIZE } from '../../../core/models';
import { AssetCreateWizardComponent } from '../components/assets/asset-create-wizard/asset-create-wizard.component';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
@Injectable({
  providedIn: 'root',
})
export class AssetsGridConfig implements GridConfiguration<AssetListItem> {
  private readonly assetsService = inject(AssetsDataAdapter);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private readonly entitiesService = inject(EntitiesService);
  private readonly defaultStateValues = ['active', 'suspended', 'inactive'];
  private readonly filterState = signal<Record<string, FilterCriteria>>({
    state: {
      value: this.defaultStateValues,
      operator: 'in',
    },
  });
  private params: Record<string, string> = { clientId: '' };
  private readonly destroyRef = inject(DestroyRef);
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );
  private readonly fieldTransformations: Record<string, string> = {
    costCentre: 'costCentre.id',
    assetType: 'assetType.id',
    groups: 'groups.id',
  };

  columns: GridColumn<AssetListItem>[] = [
    {
      field: 'name',
      header: 'Name',
      filter: true,
      filterType: 'text',
      filterMatchMode: 'contains',
      transform: 'text-ellipsis',
    },
    {
      field: 'assetType',
      header: 'Type',
      valueGetter: (rowData: AssetListItem) =>
        isDefined(rowData.assetType?.name) ? rowData.assetType?.name : '',
      filterType: 'multiselect',
      filter: true,
      filterMatchMode: 'in',
      filterConfig: {
        type: 'multiselect',
        options: [],
      },
    },
    {
      field: 'state',
      header: 'State',
      filter: true,
      filterType: 'multiselect',
      filterMatchMode: 'in',
      filterConfig: {
        type: 'multiselect',
        options: [
          { label: 'Active', value: 'active' },
          { label: 'Suspended', value: 'suspended' },
          { label: 'Deleted', value: 'deleted' },
          { label: 'Inactive', value: 'inactive' },
        ],
        defaultSelected: this.defaultStateValues,
      },
      transform: 'capitalize',
    },
    {
      field: 'costCentre',
      header: 'Cost Centre',
      valueGetter: (rowData: AssetListItem) =>
        isDefined(rowData.costCentre?.name) ? rowData.costCentre?.name : '',
      filter: true,
      filterType: 'multiselect',
      filterMatchMode: 'in',
      filterConfig: {
        type: 'multiselect',
        options: [],
      },
    },
    {
      field: 'groups',
      header: 'Groups',
      valueGetter: (rowData: AssetListItem) =>
        isDefined(rowData.groups)
          ? rowData.groups.map((g) => g.name).join(', ')
          : '',
      filter: true,
      filterType: 'multiselect',
      filterMatchMode: 'in',
      filterConfig: {
        type: 'multiselect',
        options: [],
      },
    },
    {
      field: 'devices',
      header: 'Devices',
      valueGetter: (rowData: AssetListItem) =>
        isDefined(rowData.devices)
          ? rowData.devices.map((d) => d.name).join(', ')
          : '',
      filter: true,
      filterType: 'text',
    },
    {
      field: 'cameras',
      header: 'Cameras',
      filter: false,
    },
    {
      field: 'modifiedDate',
      header: 'Modified',
      filter: false,
      valueGetter: (rowData: AssetListItem) => {
        return isDefined(rowData['modifiedDate'])
          ? this.measurementDateTimeService.formatDateTime(
              new Date(rowData['modifiedDate']),
              DATE_FORMATS.DATE_TIME_SECONDS,
            )
          : rowData['modifiedDate'];
      },
    },
  ];

  dataService: GridDataService<AssetListItem> = this.assetsService;

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({
      state: {
        value: this.defaultStateValues,
        operator: 'in',
      },
    });
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
    this.loadFilterOptions();
  }

  getTitle(): string {
    return 'Assets';
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    let sortField = 'name:asc'; // Default

    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: this.params['clientId'],
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: sortField,
      filters: this.rqlFilter(),
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const actualField = this.fieldTransformations[field] || field;
    const column = this.columns.find((col) => col.field === field);

    if (Array.isArray(value)) {
      const newFilters = this.gridBaseService.handleFilters(
        this.filterState(),
        actualField,
        value,
        undefined,
        column?.filterMatchMode,
      );

      this.filterState.set(newFilters);
      return;
    }

    // For non-array values, use the grid base service
    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      actualField,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);
  }

  private loadFilterOptions(): void {
    combineLatest([
      this.entitiesService.listAssetTypes(this.params['clientId']),
      this.entitiesService.listCostCentres(this.params['clientId']),
      this.entitiesService.listAssetGroups(this.params['clientId']),
    ])
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          return EMPTY;
        }),
      )
      .subscribe(([types, costCentres, listAssetGroups]) => {
        const typeColumn = this.columns.find(
          (col) => col.field === 'assetType',
        );
        if (typeColumn?.filterConfig) {
          typeColumn.filterConfig.options = types.items
            .map((type) => ({
              label: type.name,
              value: type.id,
            }))
            .sort((a, b) => (a.label ?? '').localeCompare(b.label ?? ''));
        }

        const costCentreColumn = this.columns.find(
          (col) => col.field === 'costCentre',
        );
        if (costCentreColumn?.filterConfig) {
          costCentreColumn.filterConfig.options = costCentres.items
            .map((costCentre) => ({
              label: costCentre.name ?? '',
              value: costCentre.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label));
        }

        const groupColumn = this.columns.find((col) => col.field === 'groups');
        if (groupColumn?.filterConfig) {
          groupColumn.filterConfig.options = listAssetGroups.items
            .map((group) => ({
              label: group.name ?? '',
              value: group.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label));
        }
      });
  }

  onAdd(): void {
    const clientId = this.params['clientId'];

    this.openAssetCreationDialog(clientId).subscribe((createdAsset) => {
      if (isDefined(createdAsset)) {
        // Refresh your asset list or take any other necessary actions
        // this.refreshAssets();
      }
    });
  }

  openAssetCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(AssetCreateWizardComponent, {
      header: 'Asset Wizard',
      contentStyle: { overflow: 'auto' },
      baseZIndex: 10000,
      data: {
        ownerId: ownerId,
      },
      position: 'top',
      modal: true,
    });

    return this.dialogRef.onClose;
  }
}
