  /**
   * Confirm and execute custom field deletion
   */
  confirmCustomFieldDelete(entityId: string): Observable<unknown> {
    const resultSubject = new Subject<unknown>();

    const message = `Are you sure you want to delete this custom field?`;

    this.confirmationService.confirm({
      message,
      header: 'Confirm Delete',
      icon: 'pi pi-exclamation-triangle',
      accept: () => {
        this.deleteCustomField(entityId).subscribe({
          next: (result) => {
            this.broadcastService.broadcast('entity-deleted', {
              entityType: 'custom-field',
              operation: 'delete',
              entityId,
              data: result,
            });
            resultSubject.next(result);
          },
          error: (error) => resultSubject.error(error),
          complete: () => resultSubject.complete(),
        });
      },
      reject: () => {
        resultSubject.complete();
      },
      acceptButtonProps: { label: 'Delete' },
      rejectButtonProps: { label: 'Cancel', severity: 'secondary' },
    });

    return resultSubject.asObservable();
  }

  /**
   * Delete a custom field by removing it from the parent company's customFields array
   */
  private deleteCustomField(entityId: string): Observable<unknown> {
    if (isNullOrUndefined(entityId)) {
      return throwError(
        () => new Error('Entity ID is required for custom field deletion.'),
      );
    }

    const [companyId, entityType, fieldId] = entityId.split('.');

    if (!companyId || !entityType || !fieldId) {
      return throwError(
        () =>
          new Error(
            'Invalid custom field entity ID format. Expected: companyId.entityType.fieldId',
          ),
      );
    }

    // First get the company to determine its type and current customFields
    return this.accountsService.getCompany(companyId).pipe(
      switchMap((company) => {
        if (!company.customFields) {
          return throwError(
            () => new Error('Company has no custom fields to delete.'),
          );
        }

        // Deep clone the customFields to avoid mutation
        const customFields: Record<string, CustomFieldDefinition[]> =
          JSON.parse(JSON.stringify(company.customFields));

        // Get the current custom fields for this entity type
        const currentFields = customFields[entityType];
        if (!Array.isArray(currentFields) || currentFields.length === 0) {
          return throwError(
            () =>
              new Error(
                `No custom fields found for entity type: ${entityType}`,
              ),
          );
        }

        // Filter out the field to be deleted
        const filteredFields = currentFields.filter(
          (field) => field.id !== fieldId,
        );

        // Update the customFields object
        customFields[entityType] = filteredFields;

        // Determine the update method based on company type
        switch (company.type) {
          case 'client':
            return this.accountsService.updateClientDetails(companyId, {
              customFields,
            });
          case 'vendor':
            return this.accountsService.updateVendorDetails(companyId, {
              customFields,
            });
          case 'distributor':
            return this.accountsService.updateDistributorDetails(companyId, {
              customFields,
            });
          default:
            return throwError(
              () =>
                new Error(
                  `Unsupported company type ('${company.type}') for custom field deletion.`,
                ),
            );
        }
      }),
    );
  }

  /**
   * Toggle popover visibility
   */
  togglePopover(id: string | null): void {
    if (this.activePopover.value === id) {
      this.activePopover.next(null);
    } else {
      this.activePopover.next(id);
    }
  }

  /**
   * Update entity state
   */
  updateEntityState(
    entityType: string,
    entityId: string,
    state: string,
  ): Observable<unknown> {
    // Close popover
    this.activePopover.next(null);
    const resultSubject = new Subject<unknown>();
    const message = `
    <div class="flex flex-col gap-2">
      <div>You are about to apply the following changes to 1 item:</div>
      <div class="p-2">
        <div class="flex items-center">
          <span class="font-medium capitalize">${state}</span>
          <span class="mx-2">→</span>
          <span>Change state to <span class="capitalize">'${state}'</span></span>
        </div>
      </div>
      <div class="mt-2">Are you sure you want to continue?</div>
    </div>
  `;

    // Show confirmation
    this.confirmationService.confirm({
      message,
      header: 'Bulk Update',
      icon: 'pi pi-exclamation-triangle',
      accept: () => {
        this.executeOperation(entityType, 'updateState', entityId, {
          state,
        }).subscribe({
          next: (result) => resultSubject.next(result),
          error: (error) => resultSubject.error(error),
          complete: () => resultSubject.complete(),
        });
      },
      reject: () => {
        resultSubject.complete();
      },
      acceptButtonProps: { label: 'Apply' },
      rejectButtonProps: { label: 'Cancel', severity: 'secondary' },
    });

    return resultSubject.asObservable();
  }

  /**
   * Confirm and execute entity deletion
   */
  confirmDelete(entityType: string, entityId: string): Observable<unknown> {
    const resultSubject = new Subject<unknown>();

    const message = `Are you sure you want to delete this ${entityType.replace(/-/g, ' ')}?`;

    this.confirmationService.confirm({
      message,
      header: 'Confirm Delete',
      icon: 'pi pi-exclamation-triangle',
      accept: () => {
        this.executeOperation(entityType, 'delete', entityId).subscribe({
          next: (result) => resultSubject.next(result),
          error: (error) => resultSubject.error(error),
          complete: () => resultSubject.complete(),
        });
      },
      reject: () => {
        resultSubject.complete();
      },
      acceptButtonProps: { label: 'Delete' },
      rejectButtonProps: { label: 'Cancel', severity: 'secondary' },
    });

    return resultSubject.asObservable();
  }

  /**
   * Execute an operation on an entity
   * @returns Observable of the operation result
   */
  executeOperation(
    entityType: string,
    operationType: string,
    entityId: string,
    params?: OperationParams,
  ): Observable<unknown> {
    if (isNullOrUndefined(this.actionHandlers[entityType]?.[operationType])) {
      const errorMsg = `No handler found for operation ${operationType} on entity type ${entityType}`;
      return throwError(() => new Error(errorMsg));
    }

    const handler = this.actionHandlers[entityType][operationType];
    return handler(entityId, params || {}).pipe(
      tap((res) => {
        // Broadcast appropriate event based on operation type
        const eventType =
          operationType === 'delete' ? 'entity-deleted' : 'entity-updated';
        this.broadcastService.broadcast(eventType, {
          entityType,
          operation: operationType,
          entityId,
          data: res,
        });
      }),
      catchError((error) => {
        return throwError(() => error);
      }),
    );
  }

  /**
   * Get state options for an entity type
   */
  getStateOptions(entityType: string): StateOption[] {
    return this.stateOptions[entityType] ?? [];
  }

  /**
   * Register a new operation handler
   */
  registerOperationHandler(
    entityType: string,
    operationType: string,
    handler: (entityId: string, params: OperationParams) => Observable<unknown>,
  ): void {
    if (isNullOrUndefined(this.actionHandlers[entityType])) {
      this.actionHandlers[entityType] = {};
    }

    this.actionHandlers[entityType][operationType] = handler;
  }

  /**
   * Register state options for an entity type
   */
  registerStateOptions(entityType: string, options: StateOption[]): void {
    this.stateOptions[entityType] = options;
  }

  /**
   * Register action provider for an entity type
   */
  registerActionProvider(
    entityType: string,
    provider: (entityId: string) => ActionIcon[],
  ): void {
    this.actionProviders[entityType] = provider;
  }

