import { CommonModule } from '@angular/common';
import {
  Component,
  ViewChild,
  AfterViewInit,
  TemplateRef,
  signal,
  inject,
  OnInit,
  DestroyRef,
} from '@angular/core';
import { ReactiveFormsModule } from '@angular/forms';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { Step } from '../../../../../shared/models';
import { ButtonModule } from 'primeng/button';
import { AssetDetailsSectionComponent } from '../asset-details-section/asset-details-section.component';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { AssetCategoriesSectionComponent } from '../asset-categories-section/asset-categories-section.component';
import {
  AssetCreateRequest,
  AssetResponse,
  EntitiesService,
  IdName,
} from '../../../../../api';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';

// Interface for asset form data structure
interface AssetFormDetails {
  name?: string;
  mapIconName?: string;
  assetType?: { id: string; name: string };
  color?: string;
  costCentre?: { id: string; name: string };
  groups?: { id: string; name: string }[];
  tags?: string[];
  assetTag?: string;
  ownerId?: string;
  [key: string]: unknown; // For other dynamic properties
}

// Interface for asset categories form data
interface AssetCategoriesFormData {
  categories?: IdName[] | null;
}

@Component({
  selector: 'app-asset-create-wizard',
  standalone: true,
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    AssetDetailsSectionComponent,
    AssetCategoriesSectionComponent,
  ],
  templateUrl: './asset-create-wizard.component.html',
  styleUrl: './asset-create-wizard.component.scss',
})
export class AssetCreateWizardComponent implements AfterViewInit, OnInit {
  @ViewChild('assetDetailsStep') assetDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('assetCategoriesStep', { static: true })
  assetCategoriesStep!: TemplateRef<{ $implicit: Step }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;

  // References to form components
  @ViewChild('assetDetailsForm')
  assetDetailsForm!: AssetDetailsSectionComponent;
  @ViewChild('assetCategoriesForm')
  assetCategoriesForm!: AssetCategoriesSectionComponent;

  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);

  // Asset model to collect data across steps
  newAsset = signal<AssetCreateRequest>({} as AssetCreateRequest);

  // Form validity state
  formIsValid = signal<boolean>(false);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    setTimeout(() => {
      this.steps = [
        {
          value: 1,
          header: 'Asset Details',
          content: this.assetDetailsStep,
          complete: false,
          validate: () => this.assetDetailsForm.validate(),
        },
        {
          value: 2,
          header: 'Categories',
          content: this.assetCategoriesStep,
          complete: false,
          validate: () => this.assetCategoriesForm.validate(),
        },
        {
          value: 3,
          header: 'Confirmation',
          content: this.confirmationTemplate,
          complete: true,
        },
      ];
    });
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize asset with ownerId
      this.newAsset.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  openWizard() {
    this.displayWizard = true;
    this.newAsset.set({} as AssetCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  onCategoriesFormValidityChange(isValid: boolean) {
    this.steps[1].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  // Update the asset state with form data
  updateAssetDetails(formData: AssetFormDetails) {
    this.newAsset.update((current) => {
      const updated = { ...current };

      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  updateAssetCategories(formData: AssetCategoriesFormData) {
    this.newAsset.update((current) => {
      const updated = { ...current };

      updated.categories = isEmpty(formData.categories)
        ? null
        : formData.categories;

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  onWizardComplete(): void {
    // Process the final data from all steps
    const assetData = this.newAsset();

    this.entitiesService
      .createAsset(assetData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: AssetResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          console.error('Error creating asset:', error);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newAsset.set({} as AssetCreateRequest);
    this.dialogRef.close();
  }
}
