import { Injectable, inject } from '@angular/core';
import { ClientResponse, VendorListItem, VendorResponse } from '../../../api';
import { AdminTreeService } from './admin-tree.service';
import { AdminStateService } from './admin-state.service';
import { AdminSearchService } from './admin-search.service';
import { MessageService, TreeNode } from 'primeng/api';
import {
  DEFAULT_LIST_SIZE,
  LOCAL_STORAGE_KEY_SELECTED_CLIENT,
} from '../../../core/models';
import { AuthDataService } from '../../../core/services/auth-data.service';
import { LocalStorageService } from '../../../shared/services/local-storage.service';
import { ADMIN_TREE } from '../models/tree-node-data.interface';
import { isDefined, isNullOrUndefined } from '../../../shared/utils';
import { HttpErrorResponse } from '@angular/common/http';

@Injectable({
  providedIn: 'root',
})
export class AdminDataService {
  private readonly adminTreeService = inject(AdminTreeService);
  private readonly adminState = inject(AdminStateService);
  private readonly adminSearchService = inject(AdminSearchService);
  private readonly messageService = inject(MessageService);
  private readonly localStorageService = inject(LocalStorageService);
  private readonly authDataService = inject(AuthDataService);

  private async loadClient(routeClientId?: string): Promise<void> {
    // Priority order: 1. Route client ID, 2. Saved client ID, 3. Default client ID
    const savedClientId = this.localStorageService.getItem<
      Partial<ClientResponse>
    >(LOCAL_STORAGE_KEY_SELECTED_CLIENT)?.id;
    const defaultClientId =
      this.authDataService.getUserProfile()?.defaultClient?.id;

    // Use route client ID if provided, otherwise fall back to saved or default
    const clientIdToLoad = routeClientId ?? savedClientId ?? defaultClientId;

    if (isNullOrUndefined(clientIdToLoad)) {
      this.messageService.add({
        severity: 'warn',
        summary: 'Warning',
        detail: 'No client found for the user',
      });
      return;
    }

    try {
      const client = await this.adminTreeService.tryLoadClient(
        clientIdToLoad,
        defaultClientId,
      );
      this.adminState.setSelectedClient(client);
      if (!client) {
        this.messageService.add({
          severity: 'warn',
          summary: 'Warning',
          detail: 'No client found for the user',
        });
      }
    } catch (error: unknown) {
      this.messageService.add({
        severity: 'error',
        summary: 'Error',
        detail: `An error occurred while initializing the client:  ${error instanceof Error ? error.message : 'Unknown error'}`,
      });
    }
  }

  private async loadVendorData(ownerId: string): Promise<void> {
    try {
      const vendor = await this.adminTreeService.fetchClientVendor(ownerId);
      if (isNullOrUndefined(vendor?.id)) return;

      this.adminState.setClientVendor(vendor);
    } catch (error) {
      if (error instanceof HttpErrorResponse && error?.status === 403) {
        const selectedClient = this.adminState.selectedClient();
        if (selectedClient) {
          this.adminState.setFallbackToClient(selectedClient);
        }
      } else {
        throw error;
      }
    }
  }

  private async loadDistributorData(
    vendor: VendorResponse | VendorListItem,
  ): Promise<void> {
    try {
      const [groups, clients] = await Promise.all([
        this.adminTreeService.listCompanyGroups(vendor.id),
        this.adminTreeService.listVendorClients(
          vendor.id,
          undefined,
          0,
          DEFAULT_LIST_SIZE,
        ),
      ]);

      this.adminState.setVendorGroups(vendor.id, groups);
      this.adminState.addVendorClients(vendor.id, clients.clients, {
        offset: 0,
        limit: DEFAULT_LIST_SIZE,
        total: clients.total,
        hasMore: clients.hasMore,
      });
      this.adminState.markVendorAsLoaded(vendor.id);

      const distributor = await this.adminTreeService.fetchVendorDistributor(
        vendor.owner?.id,
      );
      if (!distributor) {
        this.adminState.setFallbackToVendor(vendor);
        return;
      }

      this.adminState.setVendorDistributor(distributor);
      this.adminState.setExpandedDistributor(distributor.id, true);

      if (!this.adminState.vendors().length) {
        const vendors = await this.adminTreeService.listDistributorVendors(
          distributor.id,
        );
        this.adminState.setVendors(vendors);
      }
    } catch (error) {
      if (error instanceof HttpErrorResponse && error?.status === 403) {
        this.adminState.setFallbackToVendor(vendor);
      } else {
        throw error;
      }
    }
  }

  /**
   * Loads the initial hierarchical data for the administration tree.
   * This includes loading client data, vendor data, and distributor data in sequence.
   * Sets loading states and handles errors during the loading process.
   *
   * @param routeClientId Optional client ID from the route parameters
   * @returns Promise<void> Resolves when all data is loaded or if an error occurs
   * @throws Displays error message via MessageService if loading fails
   */
  async loadInitialData(routeClientId?: string): Promise<void> {
    this.adminState.setInitialLoading(true);
    try {
      if (!this.adminState.hasClientData()) {
        await this.loadClient(routeClientId);
      }
      const selectedClient = this.adminState.selectedClient();
      if (isNullOrUndefined(selectedClient?.owner?.id)) return;

      if (!this.adminState.hasVendorData()) {
        await this.loadVendorData(selectedClient.owner.id);
      }
      const vendor = this.adminState.clientVendor();
      if (!vendor) return;

      // Load both groups and direct vendor clients
      const [groups, vendorClientResponse] = await Promise.all([
        this.adminTreeService.listCompanyGroups(vendor.id),
        this.adminTreeService.listVendorClients(
          vendor.id,
          undefined,
          0,
          DEFAULT_LIST_SIZE,
        ), // First page
      ]);

      this.adminState.setVendorGroups(vendor.id, groups);
      this.adminState.addVendorClients(
        vendor.id,
        vendorClientResponse.clients,
        {
          offset: 0,
          limit: DEFAULT_LIST_SIZE,
          total: vendorClientResponse.total,
          hasMore: vendorClientResponse.hasMore,
        },
        false, // Replace on initial load
      );
      this.adminState.markVendorAsLoaded(vendor.id);

      // If client belongs to a group, load that group's clients
      if (isDefined(selectedClient.group)) {
        const groupClientResponse =
          await this.adminTreeService.listVendorClients(
            vendor.id,
            selectedClient.group,
            0,
            DEFAULT_LIST_SIZE,
          );
        this.adminState.addGroupClients(
          vendor.id,
          selectedClient.group,
          groupClientResponse.clients,
          {
            offset: 0,
            limit: DEFAULT_LIST_SIZE,
            total: groupClientResponse.total,
            hasMore: groupClientResponse.hasMore,
          },
          false, // Replace on initial load
        );
        this.adminState.setExpandedGroup(selectedClient.group, true);
      }

      // Expand the vendor node
      this.adminState.toggleNodeExpansion(vendor.id, true);

      if (vendor.owner?.id) {
        await this.loadDistributorData(vendor);
      }
    } catch (error: unknown) {
      this.messageService.add({
        severity: 'error',
        summary: 'Error',
        detail: `Failed to load initial data:  ${error instanceof Error ? error.message : 'Unknown error'}`,
      });
    } finally {
      this.adminState.setInitialLoading(false);

      // Start background search data preloading for better search performance
      // This runs in the background and doesn't block the UI
      this.preloadSearchDataInBackground();
    }
  }

  /**
   * Preloads search data in the background to improve search performance
   * This method runs asynchronously and doesn't block the UI
   */
  private preloadSearchDataInBackground(): void {
    // Run preloading in background without waiting
    this.adminSearchService.preloadSearchData().catch((error) => {
      console.warn('Background search data preloading failed:', error);
      // Don't show user-facing error for background operation
    });
  }

  /**
   * Expands a tree node and loads its children data.
   * For vendor nodes, loads company groups and clients.
   * For group nodes, loads the associated clients.
   *
   * @param node - The TreeNode to expand
   * @returns Promise<void> Resolves when child data is loaded
   * @throws Displays error message via MessageService if loading fails
   */
  async expandNode(node: TreeNode): Promise<void> {
    if (
      isNullOrUndefined(node.data?.id) ||
      node.type !== ADMIN_TREE.NODE_TYPES.VENDOR
    )
      return;
    const vendorId = node.data.id;

    // Avoid reloading if already loaded (optional, adjust if needed)
    if (this.adminState.loadedVendors().has(vendorId)) return;

    try {
      this.adminState.addLoadingVendor(vendorId);
      this.adminState.toggleNodeExpansion(vendorId, true);

      const [groups, clientResponse] = await Promise.all([
        this.adminTreeService.listCompanyGroups(vendorId),
        this.adminTreeService.listVendorClients(
          vendorId,
          undefined,
          0,
          DEFAULT_LIST_SIZE,
        ), // First page
      ]);

      this.adminState.setVendorGroups(vendorId, groups);
      this.adminState.addVendorClients(
        vendorId,
        clientResponse.clients,
        {
          offset: 0,
          limit: DEFAULT_LIST_SIZE,
          total: clientResponse.total,
          hasMore: clientResponse.hasMore,
        },
        false, // Replace on initial expand
      );
      this.adminState.markVendorAsLoaded(vendorId);
    } catch (error: unknown) {
      this.adminState.markVendorAsFailed(vendorId);
      this.messageService.add({
        severity: 'error',
        summary: 'Error',
        detail: `Failed to load vendor data: ${error instanceof Error ? error.message : 'Unknown error'}`,
      });
    } finally {
      this.adminState.removeLoadingVendor(vendorId);
    }
  }

  /**
   * Expands a group node and loads its associated clients.
   *
   * @param groupNode - The group TreeNode to expand
   * @returns Promise<void> Resolves when client data is loaded
   * @throws Displays error message via MessageService if loading fails
   */
  async expandGroup(groupNode: TreeNode): Promise<void> {
    if (
      isNullOrUndefined(groupNode.data?.id) ||
      isNullOrUndefined(groupNode.parent?.data?.id)
    )
      return;
    const groupId = groupNode.data.id;
    const vendorId = groupNode.parent.data.id;

    // Avoid reloading if already loaded (check pagination state)
    const paginationKey = `${vendorId}_${groupId}`;
    if (isDefined(this.adminState.clientPagination()[paginationKey])) return;

    try {
      // Optionally add a loading state specific to the group expand
      this.adminState.setExpandedGroup(groupId, true); // Mark as expanded optimistically

      const clientResponse = await this.adminTreeService.listVendorClients(
        vendorId,
        groupId,
        0,
        DEFAULT_LIST_SIZE,
      );

      this.adminState.addGroupClients(
        vendorId,
        groupId,
        clientResponse.clients,
        {
          offset: 0,
          limit: DEFAULT_LIST_SIZE,
          total: clientResponse.total,
          hasMore: clientResponse.hasMore,
        },
        false, // Replace on initial expand
      );
    } catch (error: unknown) {
      this.adminState.setExpandedGroup(groupId, false); // Revert expansion on error
      this.messageService.add({
        severity: 'error',
        summary: 'Error',
        detail: `Failed to load group clients: ${error instanceof Error ? error.message : 'Unknown error'}`,
      });
    }
  }

  expandDistributor(distributorNode: TreeNode): void {
    this.adminState.setExpandedDistributor(distributorNode.data.id, true);
  }

  collapseNode(node: TreeNode): void {
    this.adminState.toggleNodeExpansion(node.data.id, false);
  }

  collapseGroup(groupNode: TreeNode): void {
    this.adminState.setExpandedGroup(groupNode.data.id, false);
  }

  collapseDistributor(distributorNode: TreeNode): void {
    this.adminState.setExpandedDistributor(distributorNode.data.id, false);
  }

  /**
   * Selects a node in the tree and updates the selected client in the admin state.
   *
   * @param node - The TreeNode to select
   */
  selectNode(node: TreeNode): void {
    // Prevent selecting the "Load More" node as a client
    if (
      isNullOrUndefined(node.data?.id) ||
      node.type === ADMIN_TREE.NODE_TYPES.LOAD_MORE
    )
      return;
    // Only select actual client nodes
    if (node.type === ADMIN_TREE.NODE_TYPES.CLIENT) {
      this.adminState.setSelectedClient(node.data as ClientResponse);
    } else {
      // Handle selection of vendor/group/distributor if needed,
      // or clear selection if only clients are selectable entities
      this.adminState.setSelectedClient(null);
    }
  }

  /**
   * Recursively searches through the tree nodes to find a node matching the given client ID.
   *
   * @param nodes - Array of TreeNodes to search through
   * @param clientId - The client ID to search for
   * @returns TreeNode if found, null otherwise
   */
  findSelectedNode(nodes: TreeNode[], clientId: string): TreeNode | null {
    for (const node of nodes) {
      if (node.key === clientId) {
        return node;
      }
      if (node.children) {
        const found = this.findSelectedNode(node.children, clientId);
        if (found) return found;
      }
    }
    return null;
  }

  /**
   * Loads the next page of clients for a given vendor or group.
   * @param vendorId - The ID of the vendor.
   * @param groupId - Optional group ID.
   */
  async loadMoreClients(vendorId: string, groupId?: string): Promise<void> {
    const paginationKey = isDefined(groupId)
      ? `${vendorId}_${groupId}`
      : vendorId;
    const currentPagination = this.adminState.clientPagination()[paginationKey];

    if (
      isNullOrUndefined(currentPagination) ||
      isNullOrUndefined(currentPagination.hasMore) ||
      currentPagination.loadingMore === true
    ) {
      return; // No more pages or already loading
    }

    const nextOffset = currentPagination.offset + currentPagination.limit;

    try {
      this.adminState.setLoadingMoreClients(vendorId, groupId, true);

      const clientResponse = await this.adminTreeService.listVendorClients(
        vendorId,
        groupId,
        nextOffset,
        DEFAULT_LIST_SIZE,
      );

      const paginationUpdate = {
        offset: nextOffset,
        limit: DEFAULT_LIST_SIZE,
        total: clientResponse.total,
        hasMore: clientResponse.hasMore,
      };

      if (isDefined(groupId)) {
        this.adminState.addGroupClients(
          vendorId,
          groupId,
          clientResponse.clients,
          paginationUpdate,
          true, // Append results
        );
      } else {
        this.adminState.addVendorClients(
          vendorId,
          clientResponse.clients,
          paginationUpdate,
          true, // Append results
        );
      }
    } catch (error: unknown) {
      this.messageService.add({
        severity: 'error',
        summary: 'Error',
        detail: `Failed to load more clients: ${error instanceof Error ? error.message : 'Unknown error'}`,
      });
      // Reset loading state on error
      this.adminState.setLoadingMoreClients(vendorId, groupId, false);
    }
    // Loading state is reset within addVendorClients/addGroupClients on success
  }

  /**
   * Handles client creation event to refresh the tree state.
   * This method is called when a client is created, and it refreshes the relevant parts of the tree.
   */
  async handleClientCreated(clientId: string): Promise<ClientResponse | null> {
    try {
      // Load the new client to get its details
      const client = await this.adminTreeService.tryLoadClient(clientId);
      if (!client) {
        console.warn('Could not load newly created client:', clientId);
        return null;
      }

      const vendorId = client.owner?.id;
      if (!vendorId) {
        console.warn('Client does not have a vendor ID:', clientId);
        return null;
      }

      // Check if this is a group client
      const groupId = client.group;

      // Check if vendor is currently expanded
      const isVendorExpanded = this.adminState.expandedNodes().has(vendorId);

      // Ensure vendor node is expanded to show the new client
      this.adminState.toggleNodeExpansion(vendorId, true);

      // If vendor was already expanded, force a complete reload of vendor data
      // to ensure the tree reflects the new client
      if (isVendorExpanded && this.adminState.loadedVendors().has(vendorId)) {
        // Remove from loaded vendors first to force a complete reload
        this.adminState.removeFromLoadedVendors(vendorId);

        // Clear all existing data to force a fresh reload
        this.adminState.clearVendorClients(vendorId);
        this.adminState.clearVendorPagination(vendorId);
        this.adminState.clearVendorGroups(vendorId);

        // Force a complete reload by using the data service expand method
        // This will reload both groups and clients
        const vendorNode = {
          key: vendorId,
          data: { id: vendorId },
          type: ADMIN_TREE.NODE_TYPES.VENDOR,
        } as TreeNode;

        // Reload the vendor data completely
        await this.expandNode(vendorNode);
      } else {
        // Normal path for when vendor is collapsed or not yet loaded
        // Refresh the clients for the vendor or group
        if (isDefined(groupId) && groupId.trim() !== '') {
          // For group clients, also ensure the group is expanded
          this.adminState.setExpandedGroup(groupId, true);

          // Refresh group clients
          const groupClients = await this.adminTreeService.listVendorClients(
            vendorId,
            groupId,
            0,
            this.adminState.clientPagination()[`${vendorId}_${groupId}`]
              ?.limit || 50,
          );

          this.adminState.addGroupClients(
            vendorId,
            groupId,
            groupClients.clients,
            {
              offset: 0,
              limit: groupClients.clients.length,
              total: groupClients.total,
              hasMore: groupClients.hasMore,
            },
            false, // Replace existing clients
          );
        } else {
          // Refresh direct vendor clients
          const vendorClients = await this.adminTreeService.listVendorClients(
            vendorId,
            undefined,
            0,
            this.adminState.clientPagination()[vendorId]?.limit || 50,
          );

          this.adminState.addVendorClients(
            vendorId,
            vendorClients.clients,
            {
              offset: 0,
              limit: vendorClients.clients.length,
              total: vendorClients.total,
              hasMore: vendorClients.hasMore,
            },
            false, // Replace existing clients
          );
        }

        // Mark vendor as loaded after refreshing the data
        this.adminState.markVendorAsLoaded(vendorId);
      }

      return client; // Return the client for further use by the component
    } catch (error) {
      console.error('Error handling client creation:', error);
      this.messageService.add({
        severity: 'error',
        summary: 'Error',
        detail: `Error refreshing tree after client creation: ${error instanceof Error ? error.message : 'Unknown error'}`,
      });
      throw error;
    }
  }
}
