import {
  AfterViewInit,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  EmailProviderCreateRequest,
  EmailProviderResponse,
  EmailProviderTypeResponse,
} from '../../../../../api';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { EmailProviderDetailsSectionComponent } from '../email-provider-details-section/email-provider-details-section.component';
import { Step } from '../../../../../shared/models';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { EmailProviderParametersSectionComponent } from '../email-provider-parameters-section/email-provider-parameters-section.component';
import { RequestCacheService } from '../../../../../shared/services/request-cache.service';
import { firstValueFrom } from 'rxjs';

interface FormField {
  id: string;
  title: string;
  type: string;
  value?: string | number;
  defaultValue?: string | number;
  required?: boolean;
  description?: string;
  min?: number;
  max?: number;
  values?: { key: string; value: string; fields: FormField[] }[];
}
@Component({
  selector: 'app-email-provider-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    EmailProviderDetailsSectionComponent,
    EmailProviderParametersSectionComponent,
  ],
  templateUrl: './email-provider-create-wizard.component.html',
  styleUrl: './email-provider-create-wizard.component.scss',
})
export class EmailProviderCreateWizardComponent
  implements AfterViewInit, OnInit
{
  @ViewChild('emailProviderDetailsStep')
  emailProviderDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('emailProviderParametersStep')
  emailProviderParametersStep!: TemplateRef<{
    $implicit: Step;
  }>;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;

  // References to form components
  @ViewChild('emailProviderDetailsForm')
  emailProviderDetailsForm!: EmailProviderDetailsSectionComponent;
  @ViewChild('emailProviderParametersForm')
  emailProviderParametersForm!: EmailProviderParametersSectionComponent;
  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly cacheService = inject(RequestCacheService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);

  // EmailProvider model to collect data across steps
  newEmailProvider = signal<EmailProviderCreateRequest>(
    {} as EmailProviderCreateRequest,
  );
  readonly emailProviderParametersFields = signal<
    { key: string; title: string }[] | null
  >(null);
  emailProviderType = signal<EmailProviderTypeResponse | null>(null);
  // Form validity state
  formIsValid = signal<boolean>(false);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    setTimeout(() => {
      // Only update the view-dependent properties
      this.steps[0].content = this.emailProviderDetailsStep;
      this.steps[0].validate = () => this.emailProviderDetailsForm.validate();

      this.steps[1].content = this.emailProviderParametersStep;
      this.steps[1].validate = () =>
        this.emailProviderParametersForm.validate();

      this.steps[2].content = this.confirmationTemplate;
      this.steps[2].validate = () => true;
    });
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize emailProvider with ownerId
      this.newEmailProvider.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }

    this.steps = [
      {
        value: 1,
        header: 'Email Provider Details',
        complete: false,
        content: null,
      },
      {
        value: 2,
        header: 'Email Provider Parameters',
        content: null,
        complete: false,
      },
      {
        value: 3,
        header: 'Confirmation',
        complete: true,
        content: null,
      },
    ];
  }

  openWizard() {
    this.displayWizard = true;
    this.newEmailProvider.set({} as EmailProviderCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  onParametersFormValidityChange(isValid: boolean) {
    this.steps[1].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  updateEmailProviderDetails(formData: Record<string, unknown>) {
    this.newEmailProvider.update((current) => {
      const { ownerId: _ownerId, ...rest } = formData;
      const updated = { ...current, ...rest };

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
    this.loadEmailProviderType(this.newEmailProvider()['type']?.id).catch(
      () => {},
    );
  }

  updateEmailProviderParameters(formData: Record<string, unknown>) {
    this.newEmailProvider.update((current) => {
      const updated = { ...current, ...formData };
      return updated;
    });
  }

  onWizardComplete(): void {
    const emailProviderData = this.newEmailProvider();

    if (
      isNullOrUndefined(emailProviderData) ||
      Object.keys(emailProviderData).length === 0
    ) {
      return;
    }

    this.entitiesService
      .createEmailProvider(emailProviderData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: EmailProviderResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'email-provider',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newEmailProvider.set({} as EmailProviderCreateRequest);
    this.dialogRef.close();
  }

  async loadEmailProviderType(
    emailProviderTypeId: string | undefined,
  ): Promise<void> {
    if (isNullOrUndefined(emailProviderTypeId)) return;

    try {
      const response = await this.cacheService.getOrFetchAsync(
        `emailProviderType-${emailProviderTypeId}`,
        () =>
          firstValueFrom(
            this.entitiesService.getEmailProviderType(emailProviderTypeId),
          ),
        300000,
      );

      this.emailProviderType.set(response);
      this.processEmailProviderParameters(response);
    } catch (error) {
      console.error('Failed to load email provider type:', error);
      // Optionally handle the error (show notification, reset state, etc.)
    }
  }

  private processEmailProviderParameters(
    emailProviderType: EmailProviderTypeResponse,
  ): void {
    const parameterDefinition = emailProviderType?.parameterDefinition ?? '{}';

    try {
      const params: { groups: { fields: FormField[] }[] } =
        JSON.parse(parameterDefinition);
      const fields = this.extractFieldsFromGroups(params.groups);
      this.emailProviderParametersFields.set(fields);
    } catch (error) {
      console.error('Failed to parse parameter definition:', error);
      this.emailProviderParametersFields.set([]);
    }
  }

  private extractFieldsFromGroups(
    groups: { fields: FormField[] }[],
  ): { key: string; title: string }[] {
    const fields: { key: string; title: string }[] = [];

    groups.forEach((group) => {
      group.fields.forEach((field) => {
        this.addFieldToCollection(field, fields);
        this.addConditionalFields(field, fields);
      });
    });

    return fields;
  }

  private addFieldToCollection(
    field: FormField,
    fields: { key: string; title: string }[],
  ): void {
    fields.push({
      key: field.id,
      title: field.title,
    });
  }

  private addConditionalFields(
    field: FormField,
    fields: { key: string; title: string }[],
  ): void {
    if (!field.values) return;

    field.values.forEach((value) => {
      if (isDefined(value.fields)) {
        value.fields.forEach((subField) => {
          this.addFieldToCollection(subField, fields);
          // Recursively handle nested conditional fields
          this.addConditionalFields(subField, fields);
        });
      }
    });
  }
}
