import { CommonModule } from '@angular/common';
import {
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  ZoneCreateRequest,
  ZoneResponse,
} from '../../../../../api';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import {
  isDefined,
  isNullOrUndefined,
  SpatialUtils,
} from '../../../../../shared/utils';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { GeofenceDetailsSectionComponent } from '../geofence-details-section/geofence-details-section.component';
import { MeasurementUnitType, Step } from '../../../../../shared/models';
import { GeofenceCoordinatesSectionComponent } from '../geofence-coordinates-section/geofence-coordinates-section.component';
import { MeasurementUnitsService } from '../../../../../shared/services/measurement-units/measurement-units.service';

@Component({
  selector: 'app-geofence-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    GeofenceDetailsSectionComponent,
    GeofenceCoordinatesSectionComponent,
  ],
  templateUrl: './geofence-create-wizard.component.html',
  styleUrl: './geofence-create-wizard.component.scss',
})
export class GeofenceCreateWizardComponent implements AfterViewInit, OnInit {
  @ViewChild('geofenceDetailsStep') geofenceDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('geofenceCoordinatesStep')
  geofenceCoordinatesStep!: TemplateRef<{ $implicit: Step }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;

  // References to form components
  @ViewChild('geofenceDetailsForm')
  geofenceDetailsForm!: GeofenceDetailsSectionComponent;
  @ViewChild('geofenceCoordinatesForm')
  geofenceCoordinatesForm!: GeofenceCoordinatesSectionComponent;

  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly measurementUnitsService = inject(MeasurementUnitsService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);
  private readonly cdr = inject(ChangeDetectorRef);
  private readonly shapePoints = [3, 4, 6, 8];
  private readonly shapes = ['triangle', 'square', 'hexagon', 'octagon'];
  protected geofenceCoordinates: Record<string, unknown> | undefined;

  // Geofence model to collect data across steps
  newGeofence = signal<ZoneCreateRequest>({} as ZoneCreateRequest);

  // Form validity state
  formIsValid = signal<boolean>(false);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    this.steps = [
      {
        value: 1,
        header: 'Geofence Details',
        content: this.geofenceDetailsStep,
        complete: false,
        validate: () => this.geofenceDetailsForm.validate(),
      },
      {
        value: 2,
        header: 'Geofence Coordinates',
        content: this.geofenceCoordinatesStep,
        complete: false,
        validate: () => this.geofenceCoordinatesForm.validate(),
      },
      {
        value: 3,
        header: 'Confirmation',
        content: this.confirmationTemplate,
        complete: true,
      },
    ];
    this.cdr.detectChanges();
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize geofence with ownerId
      this.newGeofence.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  openWizard() {
    this.displayWizard = true;
    this.newGeofence.set({} as ZoneCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  onCoordinatesFormValidityChange(isValid: boolean) {
    this.steps[1].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  // Update the geofence state with form data
  updateGeofenceDetails(formData: Record<string, unknown>) {
    this.newGeofence.update((current) => {
      const updated = { ...current };

      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  updateGeofenceCoordinates(formData: Record<string, unknown>) {
    this.geofenceCoordinates = formData;
    const radius = this.measurementUnitsService.toBackend(
      MeasurementUnitType.DISTANCE,
      formData['shapeRadius'] as number,
    ) as number;
    const points = SpatialUtils.generateRegularPolygon(
      { x: formData['lon'] as number, y: formData['lat'] as number },
      radius,
      this.shapePoints[this.shapes.indexOf(formData['shape'] as string)],
    );
    this.newGeofence.update((current) => ({
      ...current,
      ...formData,
      points,
    }));
  }

  onWizardComplete(): void {
    // Process the final data from all steps
    const geofenceData = this.newGeofence();

    this.entitiesService
      .createZone(geofenceData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: ZoneResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'geofence',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          // Handle error, could show message and keep dialog open
          console.error('Error creating geofence:', error);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newGeofence.set({} as ZoneCreateRequest);
    this.dialogRef.close();
  }
}
