import { CommonModule } from '@angular/common';
import {
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  AccountsService,
  UserRoleCreateRequest,
  UserRoleResponse,
} from '../../../../../api';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { UserRoleDetailsSectionComponent } from '../user-role-details-section/user-role-details-section.component';
import { Step } from '../../../../../shared/models';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';

@Component({
  selector: 'app-user-role-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    UserRoleDetailsSectionComponent,
  ],
  templateUrl: './user-role-create-wizard.component.html',
  styleUrl: './user-role-create-wizard.component.scss',
})
export class UserRoleCreateWizardComponent implements AfterViewInit, OnInit {
  @ViewChild('userRoleDetailsStep')
  userRoleDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;
  private readonly cdr = inject(ChangeDetectorRef);

  // References to form components
  @ViewChild('userRoleDetailsForm')
  userRoleDetailsForm!: UserRoleDetailsSectionComponent;

  private readonly accountsService = inject(AccountsService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);

  // UserRole model to collect data across steps
  newUserRole = signal<UserRoleCreateRequest>({} as UserRoleCreateRequest);

  // Form validity state
  formIsValid = signal<boolean>(false);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    this.steps = [
      {
        value: 1,
        header: 'User Role Details',
        content: this.userRoleDetailsStep,
        complete: false,
        validate: () => this.userRoleDetailsForm.validate(),
      },
      {
        value: 2,
        header: 'Confirmation',
        content: this.confirmationTemplate,
        complete: true,
      },
    ];
    this.cdr.detectChanges(); // Trigger change detection to update the view
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize userRole with ownerId
      this.newUserRole.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  openWizard() {
    this.displayWizard = true;
    this.newUserRole.set({} as UserRoleCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  // Update the userRole state with form data
  updateUserRoleDetails(formData: Record<string, unknown>) {
    this.newUserRole.update((current) => {
      const updated = { ...current };

      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  onWizardComplete(): void {
    // Process the final data from all steps
    const userRoleData = this.newUserRole();

    this.accountsService
      .createUserRole(userRoleData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: UserRoleResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'userrole',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          // Handle error, could show message and keep dialog open
          console.error('Error creating user role:', error);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newUserRole.set({} as UserRoleCreateRequest);
    this.dialogRef.close();
  }
}
