import { CommonModule } from '@angular/common';
import {
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  OverspeedProfileCreateRequest,
  OverspeedProfileResponse,
} from '../../../../../api';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { OverspeedProfileDetailsSectionComponent } from '../overspeed-profile-details-section/overspeed-profile-details-section.component';
import { Step } from '../../../../../shared/models';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';

@Component({
  selector: 'app-overspeed-profile-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    OverspeedProfileDetailsSectionComponent,
  ],
  templateUrl: './overspeed-profile-create-wizard.component.html',
  styleUrl: './overspeed-profile-create-wizard.component.scss',
})
export class OverspeedProfileCreateWizardComponent
  implements AfterViewInit, OnInit
{
  @ViewChild('overspeedProfileDetailsStep')
  overspeedProfileDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;
  private readonly cdr = inject(ChangeDetectorRef);

  // References to form components
  @ViewChild('overspeedProfileDetailsForm')
  overspeedProfileDetailsForm!: OverspeedProfileDetailsSectionComponent;

  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);

  // OverspeedProfile model to collect data across steps
  newOverspeedProfile = signal<OverspeedProfileCreateRequest>(
    {} as OverspeedProfileCreateRequest,
  );

  // Form validity state
  formIsValid = signal<boolean>(false);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    this.steps = [
      {
        value: 1,
        header: 'Overspeed Profile Details',
        content: this.overspeedProfileDetailsStep,
        complete: false,
        validate: () => this.overspeedProfileDetailsForm.validate(),
      },
      {
        value: 2,
        header: 'Confirmation',
        content: this.confirmationTemplate,
        complete: true,
      },
    ];
    this.cdr.detectChanges(); // Trigger change detection to update the view
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize overspeedProfile with ownerId
      this.newOverspeedProfile.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  openWizard() {
    this.displayWizard = true;
    this.newOverspeedProfile.set({} as OverspeedProfileCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  // Update the overspeedProfile state with form data
  updateOverspeedProfileDetails(formData: Record<string, unknown>) {
    this.newOverspeedProfile.update((current) => {
      const updated = { ...current };

      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  onWizardComplete(): void {
    // Process the final data from all steps
    const overspeedProfileData = this.newOverspeedProfile();

    this.entitiesService
      .createOverspeedProfile(overspeedProfileData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: OverspeedProfileResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'overspeed-profile',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          // Handle error, could show message and keep dialog open
          console.error('Error creating overspeed profile:', error);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newOverspeedProfile.set({} as OverspeedProfileCreateRequest);
    this.dialogRef.close();
  }
}
