import { CommonModule } from '@angular/common';
import {
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  AlertCreateRequest,
  AlertResponse,
  AlertNotify,
} from '../../../../../api';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { AlertDetailsSectionComponent } from '../alert-details-section/alert-details-section.component';
import { Step } from '../../../../../shared/models';
import { AlertIconStorageService } from '../../../../../shared/services/alert-icon-storage.service';

@Component({
  selector: 'app-alert-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    AlertDetailsSectionComponent,
  ],
  templateUrl: './alert-create-wizard.component.html',
  styleUrl: './alert-create-wizard.component.scss',
})
export class AlertCreateWizardComponent implements AfterViewInit, OnInit {
  @ViewChild('alertDetailsStep') alertDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;

  // References to form components
  @ViewChild('alertDetailsForm')
  alertDetailsForm!: AlertDetailsSectionComponent;

  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);
  private readonly cdr = inject(ChangeDetectorRef);
  private readonly alertIconStorageService = inject(AlertIconStorageService);

  // Alert model to collect data across steps
  newAlert = signal<AlertCreateRequest>({} as AlertCreateRequest);

  // Form validity state
  formIsValid = signal<boolean>(false);

  steps: Step[] = [];
  ownerId: string | null = null;

  ngAfterViewInit() {
    this.steps = [
      {
        value: 1,
        header: 'Alert Details',
        content: this.alertDetailsStep,
        complete: false,
        validate: () => this.alertDetailsForm.validate(),
      },
      {
        value: 2,
        header: 'Confirmation',
        content: this.confirmationTemplate,
        complete: true,
      },
    ];
    this.cdr.detectChanges();
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize alert with ownerId
      this.newAlert.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  openWizard() {
    this.newAlert.set({} as AlertCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  // Update the alert state with form data
  updateAlertDetails(formData: Record<string, unknown>) {
    this.newAlert.update((current) => {
      const updated = { ...current };

      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  onWizardComplete(): void {
    // Process the final data from all steps
    const alertData = this.newAlert();

    // Extract iconName for separate storage
    const iconName = (alertData as unknown as { iconName?: string })?.iconName;

    // Create API data without iconName
    const { iconName: _, ...apiAlertData } = alertData as unknown as {
      iconName?: string;
    } & AlertCreateRequest;

    this.entitiesService
      .createAlert(apiAlertData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: AlertResponse) => {
          // Save the icon name to storage after successful creation
          if (isDefined(iconName) && iconName !== '') {
            this.alertIconStorageService.setAlertIcon(response.id, iconName);
          }

          this.broadcastService.broadcast('entity-updated', {
            entityType: 'alert',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          // Handle error, could show message and keep dialog open
          console.error('Error creating alert:', error);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newAlert.set({} as AlertCreateRequest);
    this.dialogRef.close();
  }

  getNotificationIndividualNames(
    notify: AlertNotify[] | null | undefined,
  ): string {
    if (!notify) return '';
    return notify.map((individual) => individual.name).join(', ');
  }
}
