import { CommonModule } from '@angular/common';
import {
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  AssetGroupCreateRequest,
  AssetGroupResponse,
} from '../../../../../api';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { AssetGroupDetailsSectionComponent } from '../asset-group-details-section/asset-group-details-section.component';
import { Step } from '../../../../../shared/models';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';

@Component({
  selector: 'app-asset-group-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    AssetGroupDetailsSectionComponent,
  ],
  templateUrl: './asset-group-create-wizard.component.html',
  styleUrl: './asset-group-create-wizard.component.scss',
})
export class AssetGroupCreateWizardComponent implements AfterViewInit, OnInit {
  @ViewChild('assetGroupDetailsStep')
  assetGroupDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;

  // References to form components
  @ViewChild('assetGroupDetailsForm')
  assetGroupDetailsForm!: AssetGroupDetailsSectionComponent;

  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);
  private readonly cdr = inject(ChangeDetectorRef);

  // AssetGroup model to collect data across steps
  newAssetGroup = signal<AssetGroupCreateRequest>(
    {} as AssetGroupCreateRequest,
  );

  // Form validity state
  formIsValid = signal<boolean>(false);

  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    this.steps = [
      {
        value: 1,
        header: 'Asset Group Details',
        content: this.assetGroupDetailsStep,
        complete: false,
        validate: () => this.assetGroupDetailsForm.validate(),
      },
      {
        value: 2,
        header: 'Confirmation',
        content: this.confirmationTemplate,
        complete: true,
      },
    ];
    this.cdr.detectChanges();
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize assetGroup with ownerId
      this.newAssetGroup.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  openWizard() {
    this.newAssetGroup.set({} as AssetGroupCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  // Update the assetGroup state with form data
  updateAssetGroupDetails(formData: Record<string, unknown>) {
    this.newAssetGroup.update((current) => {
      const updated = { ...current };

      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  onWizardComplete(): void {
    // Process the final data from all steps
    const assetGroupData = this.newAssetGroup();

    this.entitiesService
      .createAssetGroup(assetGroupData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: AssetGroupResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset-group',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          // Handle error, could show message and keep dialog open
          console.error('Error creating asset group:', error);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newAssetGroup.set({} as AssetGroupCreateRequest);
    this.dialogRef.close();
  }
}
