import { inject, Injectable, signal, computed } from '@angular/core';
import {
  BehaviorSubject,
  combineLatest,
  debounceTime,
  distinctUntilChanged,
  switchMap,
  of,
  Observable,
} from 'rxjs';
import { AdminTreeService } from './admin-tree.service';
import { AdminStateService } from './admin-state.service';
import { RequestCacheService } from '../../../shared/services/request-cache.service';
import { isDefined } from '../../../shared/utils';
import {
  ClientListItem,
  CompanyGroupResponse,
  VendorListItem,
} from '../../../api';
import { ADMIN_TREE } from '../models';
import { TreeSearchResult } from '../../../shared/models';

export interface SearchState {
  query: string;
  results: TreeSearchResult[];
  isSearching: boolean;
  expandedForSearch: Set<string>;
  highlightedNodes: Set<string>;
}

@Injectable({
  providedIn: 'root',
})
export class AdminSearchService {
  private readonly adminTreeService = inject(AdminTreeService);
  private readonly adminState = inject(AdminStateService);
  private readonly cacheService = inject(RequestCacheService);

  private readonly searchQuery$ = new BehaviorSubject<string>('');
  private readonly searchState = signal<SearchState>({
    query: '',
    results: [],
    isSearching: false,
    expandedForSearch: new Set(),
    highlightedNodes: new Set(),
  });

  // Public computed values
  readonly query = computed(() => this.searchState().query);
  readonly results = computed(() => this.searchState().results);
  readonly isSearching = computed(() => this.searchState().isSearching);
  readonly expandedForSearch = computed(
    () => this.searchState().expandedForSearch,
  );
  readonly highlightedNodes = computed(
    () => this.searchState().highlightedNodes,
  );
  readonly hasResults = computed(() => this.searchState().results.length > 0);
  readonly hasQuery = computed(
    () => this.searchState().query.trim().length > 0,
  );

  constructor() {
    this.setupSearchStream();
  }

  private setupSearchStream(): void {
    this.searchQuery$
      .pipe(
        debounceTime(300),
        distinctUntilChanged(),
        switchMap((query) => this.performSearch(query)),
      )
      .subscribe((results) => {
        this.updateTreeSearchResults(results);
      });
  }

  updateQuery(query: string): void {
    const trimmedQuery = query.trim();
    // Only update and trigger a search if the effective query has changed.
    if (trimmedQuery !== this.query()) {
      this.searchState.update((state) => ({
        ...state,
        query: trimmedQuery,
        isSearching: trimmedQuery.length > 0,
      }));
      this.searchQuery$.next(trimmedQuery);
    }
  }

  clearSearch(): void {
    this.searchState.set({
      query: '',
      results: [],
      isSearching: false,
      expandedForSearch: new Set(),
      highlightedNodes: new Set(),
    });
    this.searchQuery$.next('');
  }

  private performSearch(query: string): Observable<TreeSearchResult[]> {
    if (!query || query.length < 2) {
      return of([]);
    }

    const loadedResults = this.searchLoadedNodes(query);
    const apiResults = this.searchViaAPI(query);

    return combineLatest([of(loadedResults), apiResults]).pipe(
      switchMap(([loaded, api]) => {
        const combined = this.combineAndDeduplicateResults(loaded, api);
        return of(combined);
      }),
    );
  }

  private searchLoadedNodes(query: string): TreeSearchResult[] {
    const results: TreeSearchResult[] = [];
    const lowercaseQuery = query.toLowerCase();

    // Search through vendor clients
    const vendorClients = this.adminState.vendorClients();
    Object.entries(vendorClients).forEach(([vendorId, clients]) => {
      clients.forEach((client) => {
        if (client.name?.toLowerCase().includes(lowercaseQuery)) {
          results.push(this.createClientTreeSearchResult(client, vendorId));
        }
      });
    });

    // Search through group clients
    const groupClients = this.adminState.groupClients();
    Object.entries(groupClients).forEach(([vendorId, groups]) => {
      Object.entries(groups).forEach(([groupId, clients]) => {
        clients.forEach((client) => {
          if (client.name?.toLowerCase().includes(lowercaseQuery)) {
            results.push(
              this.createGroupClientTreeSearchResult(client, vendorId, groupId),
            );
          }
        });
      });
    });

    // Search through vendor groups
    const vendorGroups = this.adminState.vendorGroups();
    Object.entries(vendorGroups).forEach(([vendorId, groups]) => {
      groups.forEach((group) => {
        if (group.name?.toLowerCase().includes(lowercaseQuery) ?? false) {
          results.push(this.createGroupTreeSearchResult(group, vendorId));
        }
      });
    });

    // Search through vendors
    const vendors = this.adminState.vendors();
    vendors.forEach((vendor) => {
      if (vendor.name?.toLowerCase().includes(lowercaseQuery) ?? false) {
        results.push(this.createVendorTreeSearchResult(vendor));
      }
    });

    return results;
  }
  private async searchViaAPI(query: string): Promise<TreeSearchResult[]> {
    const results: TreeSearchResult[] = [];

    try {
      // Search clients across all vendors
      const vendors = this.adminState.vendors();
      const searchPromises = vendors.map(async (vendor) => {
        try {
          // 1. Search direct vendor clients using server-side search
          const directClientResponse =
            await this.adminTreeService.listVendorClients(
              vendor.id,
              undefined,
              0,
              50, // Limit search results
              query, // Pass search query to server
            );

          const directClients = directClientResponse.clients.map((client) =>
            this.createClientTreeSearchResult(client, vendor.id),
          );

          // 2. Load ALL company groups for this vendor (with caching)
          const allGroups = await this.loadAllVendorGroups(vendor.id);

          // 3. Search groups by name
          const matchingGroups = allGroups.filter(
            (group) =>
              group.name?.toLowerCase().includes(query.toLowerCase()) ?? false,
          );
          const groupResults = matchingGroups.map((group) =>
            this.createGroupTreeSearchResult(group, vendor.id),
          );

          // 4. Search ALL group clients (even unloaded ones)
          const allGroupClients = await this.searchAllGroupClients(
            vendor.id,
            allGroups,
            query,
          );

          return [...directClients, ...groupResults, ...allGroupClients];
        } catch (error) {
          console.warn(`Search failed for vendor ${vendor.id}:`, error);
          return [];
        }
      });

      const vendorResults = await Promise.all(searchPromises);
      results.push(...vendorResults.flat());
    } catch (error) {
      console.warn('API search failed:', error);
    }

    return results;
  }

  /**
   * Loads all company groups for a vendor with intelligent caching
   */
  private async loadAllVendorGroups(
    vendorId: string,
  ): Promise<CompanyGroupResponse[]> {
    const cacheKey = `admin-search-all-groups-${vendorId}`;

    return this.cacheService.getOrFetchAsync(
      cacheKey,
      () => this.adminTreeService.listCompanyGroups(vendorId),
      300000, // Cache for 5 minutes
    );
  }

  /**
   * Searches through ALL group clients for a vendor, loading them if necessary
   */
  private async searchAllGroupClients(
    vendorId: string,
    groups: CompanyGroupResponse[],
    query: string,
  ): Promise<TreeSearchResult[]> {
    const groupSearchPromises = groups.map(async (group) => {
      try {
        // Use caching to avoid repeated API calls for the same group search
        const cacheKey = `admin-search-group-clients-${vendorId}-${group.id}-${query}`;

        const groupClientResponse = await this.cacheService.getOrFetchAsync(
          cacheKey,
          () =>
            this.adminTreeService.listVendorClients(
              vendorId,
              group.id,
              0,
              100, // Increased limit for search
              query, // Pass search query to server
            ),
          60000, // Cache for 1 minute (shorter for search results)
        );

        return groupClientResponse.clients.map((client) =>
          this.createGroupClientTreeSearchResult(client, vendorId, group.id),
        );
      } catch (error) {
        console.warn(`Failed to search clients in group ${group.id}:`, error);
        return [];
      }
    });

    const groupClientResults = await Promise.all(groupSearchPromises);
    return groupClientResults.flat();
  }

  private combineAndDeduplicateResults(
    loaded: TreeSearchResult[],
    api: TreeSearchResult[],
  ): TreeSearchResult[] {
    const resultMap = new Map<string, TreeSearchResult>();

    // Add loaded results first (they have priority)
    loaded.forEach((result) => {
      resultMap.set(result.id, result);
    });

    // Add API results if not already present
    api.forEach((result) => {
      if (!resultMap.has(result.id)) {
        resultMap.set(result.id, result);
      }
    });

    return Array.from(resultMap.values()).sort(
      (a, b) => a.name?.localeCompare(b.name ?? '') ?? 0,
    );
  }

  private createClientTreeSearchResult(
    client: ClientListItem,
    vendorId: string,
  ): TreeSearchResult {
    const vendor = this.adminState.getVendorById(vendorId);
    const distributor = this.adminState.vendorDistributor();

    const path: string[] = [];
    const parentIds: string[] = [];

    if (distributor) {
      path.push(distributor.name ?? 'Distributor');
      parentIds.push(distributor.id);
    }

    if (vendor) {
      path.push(vendor.name ?? 'Vendor');
      parentIds.push(vendor.id);
    }

    path.push(client.name ?? 'Client');

    return {
      id: client.id,
      name: client.name ?? '',
      type: ADMIN_TREE.NODE_TYPES.CLIENT,
      path,
      parentIds,
      matched: true,
    };
  }

  private createGroupClientTreeSearchResult(
    client: ClientListItem,
    vendorId: string,
    groupId: string,
  ): TreeSearchResult {
    const vendor = this.adminState.getVendorById(vendorId);
    const distributor = this.adminState.vendorDistributor();

    const path: string[] = [];
    const parentIds: string[] = [];

    if (distributor) {
      path.push(distributor.name ?? 'Distributor');
      parentIds.push(distributor.id);
    }

    if (vendor) {
      path.push(vendor.name ?? 'Vendor');
      parentIds.push(vendor.id);
    }

    // Add the group to both path and parentIds
    const vendorGroups = this.adminState.vendorGroups()[vendorId] ?? [];
    const group = vendorGroups.find((g) => g.id === groupId);

    if (group) {
      path.push(group.name ?? 'Group');
      parentIds.push(group.id);
    } else {
      // If group is not in loaded state (during API search), we still need the groupId
      // We'll use a placeholder name but include the ID
      path.push('Group');
      parentIds.push(groupId);
    }

    path.push(client.name ?? 'Client');

    return {
      id: client.id,
      name: client.name ?? '',
      type: ADMIN_TREE.NODE_TYPES.CLIENT,
      path,
      parentIds,
      matched: true,
    };
  }

  private createGroupTreeSearchResult(
    group: CompanyGroupResponse,
    vendorId: string,
  ): TreeSearchResult {
    const vendor = this.adminState.getVendorById(vendorId);
    const distributor = this.adminState.vendorDistributor();

    const path: string[] = [];
    const parentIds: string[] = [];

    if (distributor) {
      path.push(distributor.name ?? 'Distributor');
      parentIds.push(distributor.id);
    }

    if (vendor) {
      path.push(vendor.name ?? 'Vendor');
      parentIds.push(vendor.id);
    }

    path.push(group.name ?? 'Group');

    return {
      id: group.id,
      name: group.name ?? '',
      type: ADMIN_TREE.NODE_TYPES.GROUP,
      path,
      parentIds,
      matched: true,
    };
  }

  private createVendorTreeSearchResult(vendor: {
    id: string;
    name?: string | null;
  }): TreeSearchResult {
    const distributor = this.adminState.vendorDistributor();

    const path: string[] = [];
    const parentIds: string[] = [];

    if (distributor) {
      path.push(distributor.name ?? 'Distributor');
      parentIds.push(distributor.id);
    }

    path.push(vendor.name ?? 'Vendor');

    return {
      id: vendor.id,
      name: vendor.name ?? '',
      type: ADMIN_TREE.NODE_TYPES.VENDOR,
      path,
      parentIds,
      matched: true,
    };
  }

  private updateTreeSearchResults(results: TreeSearchResult[]): void {
    const highlightedNodes = new Set(results.map((r) => r.id));
    const expandedForSearch = new Set<string>();

    // Add parent IDs to expansion set
    results.forEach((result) => {
      result.parentIds.forEach((parentId) => {
        expandedForSearch.add(parentId);
      });
    });

    this.searchState.update((state) => ({
      ...state,
      results,
      isSearching: false,
      highlightedNodes,
      expandedForSearch,
    }));
  }

  isNodeHighlighted(nodeId: string): boolean {
    return this.highlightedNodes().has(nodeId);
  }

  shouldExpandForSearch(nodeId: string): boolean {
    return this.expandedForSearch().has(nodeId);
  }

  async prepareResultForNavigation(result: TreeSearchResult): Promise<void> {
    // Ensure all parent nodes are loaded and expanded before navigation
    await this.ensureParentNodesLoaded(result);

    // Clear search after navigation
    this.clearSearch();
  }

  async ensureParentNodesLoaded(result: TreeSearchResult): Promise<void> {
    for (const parentId of result.parentIds) {
      const parentNode = this.findNodeInState(parentId);

      if (parentNode) {
        await this.loadParentNode(parentNode, parentId);
      } else {
        await this.handleUnknownParent(result.parentIds, parentId);
      }
    }
  }

  private async loadParentNode(
    parentNode: { id: string; type: string },
    parentId: string,
  ): Promise<void> {
    switch (parentNode.type) {
      case ADMIN_TREE.NODE_TYPES.DISTRIBUTOR:
        // Ensure distributor is expanded
        this.adminState.setExpandedDistributor(parentId, true);
        break;

      case ADMIN_TREE.NODE_TYPES.VENDOR:
        // Ensure vendor node is loaded and expanded
        if (!this.adminState.loadedVendors().has(parentId)) {
          await this.loadVendorData(parentId);
        }
        this.adminState.toggleNodeExpansion(parentId, true);
        break;

      case ADMIN_TREE.NODE_TYPES.GROUP: {
        // Ensure group is expanded and its clients are loaded
        const vendorId = this.findVendorIdForGroup(parentId);
        if (isDefined(vendorId)) {
          await this.loadGroupData(vendorId, parentId);
          this.adminState.setExpandedGroup(parentId, true);
        }
        break;
      }
    }
  }

  private async loadVendorData(vendorId: string): Promise<void> {
    try {
      // Load vendor groups and direct clients
      const [groups, clientResponse] = await Promise.all([
        this.adminTreeService.listCompanyGroups(vendorId),
        this.adminTreeService.listVendorClients(vendorId, undefined, 0, 100),
      ]);

      this.adminState.setVendorGroups(vendorId, groups);
      this.adminState.addVendorClients(vendorId, clientResponse.clients, {
        offset: 0,
        limit: 100,
        total: clientResponse.total,
        hasMore: clientResponse.hasMore,
      });
      this.adminState.markVendorAsLoaded(vendorId);
    } catch (error) {
      console.error(`Failed to load vendor data for ${vendorId}:`, error);
    }
  }

  private async loadGroupData(
    vendorId: string,
    groupId: string,
  ): Promise<void> {
    try {
      // Check if group clients are already loaded
      const paginationKey = `${vendorId}_${groupId}`;
      if (isDefined(this.adminState.clientPagination()[paginationKey])) {
        return; // Already loaded
      }

      const clientResponse = await this.adminTreeService.listVendorClients(
        vendorId,
        groupId,
        0,
        100,
      );

      this.adminState.addGroupClients(
        vendorId,
        groupId,
        clientResponse.clients,
        {
          offset: 0,
          limit: 100,
          total: clientResponse.total,
          hasMore: clientResponse.hasMore,
        },
      );
    } catch (error) {
      console.error(
        `Failed to load group data for ${vendorId}/${groupId}:`,
        error,
      );
    }
  }

  /**
   * Proactively loads and caches all vendor groups and their first page of clients
   * This can be called in the background to improve search performance
   */
  async preloadSearchData(): Promise<void> {
    const vendors = this.adminState.vendors();

    // Load all groups for all vendors in parallel with caching
    const preloadPromises = vendors.map(async (vendor) => {
      try {
        // Load all groups for this vendor (cached)
        const groups = await this.loadAllVendorGroups(vendor.id);

        // Optionally preload first page of clients for each group
        // This is more aggressive caching but improves search responsiveness
        const clientPreloadPromises = groups.map(async (group) => {
          const cacheKey = `admin-search-group-clients-preload-${vendor.id}-${group.id}`;

          return this.cacheService.getOrFetchAsync(
            cacheKey,
            () =>
              this.adminTreeService.listVendorClients(
                vendor.id,
                group.id,
                0,
                50, // First page only for preloading
              ),
            180000, // Cache for 3 minutes
          );
        });

        // Execute client preloading, but don't wait for it to complete
        // This is background loading
        Promise.all(clientPreloadPromises).catch((error) => {
          console.warn(
            `Background client preloading failed for vendor ${vendor.id}:`,
            error,
          );
        });
      } catch (error) {
        console.warn(
          `Failed to preload search data for vendor ${vendor.id}:`,
          error,
        );
      }
    });

    await Promise.all(preloadPromises);
  }

  /**
   * Clears search-related cache entries
   * Call this when vendor data changes to ensure fresh search results
   */
  clearSearchCache(): void {
    // Clear group cache entries
    const vendors = this.adminState.vendors();
    vendors.forEach((vendor) => {
      this.cacheService.clearCache(`admin-search-all-groups-${vendor.id}`);
    });

    // Note: Individual search result caches will expire naturally due to shorter TTL
  }

  private findNodeInState(nodeId: string): { id: string; type: string } | null {
    // Check distributor
    const distributor = this.adminState.vendorDistributor();
    if (distributor?.id === nodeId) {
      return { id: distributor.id, type: ADMIN_TREE.NODE_TYPES.DISTRIBUTOR };
    }

    // Check vendors
    const vendors = this.adminState.vendors();
    const vendor = vendors.find((v) => v.id === nodeId);
    if (vendor) {
      return { id: vendor.id, type: ADMIN_TREE.NODE_TYPES.VENDOR };
    }

    // Check groups
    const vendorGroups = this.adminState.vendorGroups();
    for (const groups of Object.values(vendorGroups)) {
      const group = groups.find((g) => g.id === nodeId);
      if (group) {
        return { id: group.id, type: ADMIN_TREE.NODE_TYPES.GROUP };
      }
    }

    return null;
  }

  private async handleUnknownParent(
    parentIds: string[],
    parentId: string,
  ): Promise<void> {
    console.warn(
      `Parent node ${parentId} not found in state, attempting to infer type`,
    );

    const vendorInParents = this.findVendorInParents(parentIds);
    if (isDefined(vendorInParents)) {
      await this.loadGroupData(vendorInParents, parentId);
      this.adminState.setExpandedGroup(parentId, true);
    }
  }

  private findVendorInParents(parentIds: string[]): string | null {
    const vendors = this.adminState.vendors();
    return parentIds.find((id) => vendors.some((v) => v.id === id)) ?? null;
  }

  private findVendorIdForGroup(groupId: string): string | null {
    const vendorGroups = this.adminState.vendorGroups();
    for (const [vendorId, groups] of Object.entries(vendorGroups)) {
      if (groups.some((group) => group.id === groupId)) {
        return vendorId;
      }
    }
    return null;
  }

  /**
   * Creates a TreeSearchResult object for a given client.
   * This is used to prepare for navigation from outside the search component,
   * e.g., from a 'View in Tree' action.
   * @param client The client list item.
   * @param vendorId The ID of the parent vendor.
   * @param groupId The optional ID of the parent group.
   * @returns A TreeSearchResult object.
   */
  createSearchResultForClient(
    client: ClientListItem,
    vendorId: string,
    groupId?: string,
  ): TreeSearchResult {
    if (isDefined(groupId)) {
      return this.createGroupClientTreeSearchResult(client, vendorId, groupId);
    }
    return this.createClientTreeSearchResult(client, vendorId);
  }

  /**
   * Creates a TreeSearchResult object for a given vendor.
   * @param vendor The vendor list item.
   * @returns A TreeSearchResult object.
   */
  createSearchResultForVendor(vendor: {
    id: string;
    name?: string | null;
  }): TreeSearchResult {
    return this.createVendorTreeSearchResult(vendor);
  }

  /**
   * Finds the vendor and group IDs for a given client by searching through all loaded data.
   * This is useful when you have a client ID but need to determine its hierarchy.
   * @param clientId The ID of the client to find
   * @returns Object containing vendorId and optional groupId, or null if not found
   */
  findClientHierarchy(
    clientId: string,
  ): { vendorId: string; groupId?: string } | null {
    // Search through direct vendor clients
    const vendorClients = this.adminState.vendorClients();
    for (const [vendorId, clients] of Object.entries(vendorClients)) {
      if (clients.some((client) => client.id === clientId)) {
        return { vendorId };
      }
    }

    // Search through group clients
    const groupClients = this.adminState.groupClients();
    for (const [vendorId, groups] of Object.entries(groupClients)) {
      for (const [groupId, clients] of Object.entries(groups)) {
        if (clients.some((client) => client.id === clientId)) {
          return { vendorId, groupId };
        }
      }
    }

    return null;
  }

  /**
   * Ensures a client node can be properly selected in the tree by loading all necessary parent nodes.
   * This is particularly useful when a client from a different hierarchy needs to be selected
   * after page refresh or navigation.
   * @param clientId The ID of the client to prepare for selection
   * @param vendorId The ID of the parent vendor
   * @param groupId Optional ID of the parent group
   * @returns Promise that resolves when all parent nodes are loaded and ready for selection
   */
  async ensureClientNodeSelectable(
    clientId: string,
    vendorId: string,
    groupId?: string,
  ): Promise<TreeSearchResult | null> {
    try {
      // First, find the client in the appropriate collection
      let client: ClientListItem | undefined;

      if (isDefined(groupId)) {
        // Look for client in group clients
        const groupClients =
          this.adminState.groupClients()[vendorId]?.[groupId];
        client = groupClients?.find((c) => c.id === clientId);

        // If not found in loaded state, try to load the group
        if (!client) {
          await this.loadGroupData(vendorId, groupId);
          const updatedGroupClients =
            this.adminState.groupClients()[vendorId]?.[groupId];
          client = updatedGroupClients?.find((c) => c.id === clientId);
        }
      } else {
        // Look for client in direct vendor clients
        const vendorClients = this.adminState.vendorClients()[vendorId];
        client = vendorClients?.find((c) => c.id === clientId);

        // If not found in loaded state, try to load vendor clients
        if (!client) {
          await this.loadVendorData(vendorId);
          const updatedVendorClients =
            this.adminState.vendorClients()[vendorId];
          client = updatedVendorClients?.find((c) => c.id === clientId);
        }
      }

      if (!client) {
        const groupInfo = isDefined(groupId) ? ` group ${groupId}` : '';
        console.warn(
          `Client ${clientId} not found in vendor ${vendorId}${groupInfo}`,
        );
        return null;
      }

      // Create search result for the client
      const searchResult = this.createSearchResultForClient(
        client,
        vendorId,
        groupId,
      );

      // Ensure all parent nodes are loaded and expanded
      await this.ensureParentNodesLoaded(searchResult);

      return searchResult;
    } catch (error) {
      console.error(
        `Failed to ensure client ${clientId} is selectable:`,
        error,
      );
      return null;
    }
  }

  /**
   * Comprehensive method to handle client selection across different hierarchies.
   * This method will attempt to find and load the client's hierarchy if not already loaded.
   * Use this method to resolve tree selection issues after page refresh.
   * @param clientId The ID of the client to select
   * @returns Promise that resolves with the TreeSearchResult if successful, null otherwise
   */
  async prepareClientForTreeSelection(
    clientId: string,
  ): Promise<TreeSearchResult | null> {
    // First, check if we can find the client in already loaded data
    const hierarchy = this.findClientHierarchy(clientId);

    if (hierarchy) {
      // Client found in loaded data, ensure it's selectable
      return this.ensureClientNodeSelectable(
        clientId,
        hierarchy.vendorId,
        hierarchy.groupId,
      );
    }

    // Client not found in loaded data, search across all vendors
    const vendors = this.adminState.vendors();

    for (const vendor of vendors) {
      try {
        // First, try to find in direct vendor clients
        const directClientResponse =
          await this.adminTreeService.listVendorClients(
            vendor.id,
            undefined,
            0,
            100,
            clientId, // Use clientId as search term
          );

        const directClient = directClientResponse.clients.find(
          (c) => c.id === clientId,
        );
        if (directClient) {
          // Found in direct vendor clients
          this.adminState.addVendorClients(
            vendor.id,
            directClientResponse.clients,
            {
              offset: 0,
              limit: 100,
              total: directClientResponse.total,
              hasMore: directClientResponse.hasMore,
            },
          );

          return this.ensureClientNodeSelectable(clientId, vendor.id);
        }

        // If not found in direct clients, search through groups
        const groups = await this.loadAllVendorGroups(vendor.id);

        for (const group of groups) {
          try {
            const groupClientResponse =
              await this.adminTreeService.listVendorClients(
                vendor.id,
                group.id,
                0,
                100,
                clientId, // Use clientId as search term
              );

            const groupClient = groupClientResponse.clients.find(
              (c) => c.id === clientId,
            );
            if (groupClient) {
              // Found in group clients
              this.adminState.addGroupClients(
                vendor.id,
                group.id,
                groupClientResponse.clients,
                {
                  offset: 0,
                  limit: 100,
                  total: groupClientResponse.total,
                  hasMore: groupClientResponse.hasMore,
                },
              );

              return this.ensureClientNodeSelectable(
                clientId,
                vendor.id,
                group.id,
              );
            }
          } catch (error) {
            console.warn(
              `Failed to search group ${group.id} for client ${clientId}:`,
              error,
            );
            continue;
          }
        }
      } catch (error) {
        console.warn(
          `Failed to search vendor ${vendor.id} for client ${clientId}:`,
          error,
        );
        continue;
      }
    }

    console.warn(`Client ${clientId} not found in any vendor hierarchy`);
    return null;
  }

  /**
   * Handles showing a client in the tree by preparing the tree and returning navigation info.
   * @param client The client entity to show.
   * @param vendorId The ID of the parent vendor.
   * @param groupId The optional ID of the parent group.
   * @returns Promise that resolves to the search result for navigation
   */
  async handleClientInTree(
    client: ClientListItem,
    vendorId: string,
    groupId?: string,
  ): Promise<TreeSearchResult> {
    const result = this.createSearchResultForClient(client, vendorId, groupId);

    // Use the search service's utility to expand all parent nodes
    await this.ensureParentNodesLoaded(result);

    return result;
  }

  /**
   * Handles showing a vendor in the tree by preparing the tree and returning navigation info.
   * @param vendor The vendor entity to show.
   * @returns Promise that resolves to the search result for navigation
   */
  async handleVendorInTree(vendor: VendorListItem): Promise<TreeSearchResult> {
    const result = this.createSearchResultForVendor(vendor);

    // Use the search service's utility to expand all parent nodes
    await this.ensureParentNodesLoaded(result);

    return result;
  }
}
