import { CommonModule } from '@angular/common';
import {
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  AccountsService,
  IdName,
  UserCreateRequest,
  UserResponse,
} from '../../../../../api';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { UserDetailsSectionComponent } from '../user-details-section/user-details-section.component';
import { Step } from '../../../../../shared/models';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { UserRolesSectionComponent } from '../user-roles-section/user-roles-section.component';

@Component({
  selector: 'app-user-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    UserDetailsSectionComponent,
    UserRolesSectionComponent,
  ],
  templateUrl: './user-create-wizard.component.html',
  styleUrl: './user-create-wizard.component.scss',
})
export class UserCreateWizardComponent implements AfterViewInit, OnInit {
  @ViewChild('userDetailsStep')
  userDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('userRolesStep')
  userRolesStep!: TemplateRef<{ $implicit: Step }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;
  private readonly cdr = inject(ChangeDetectorRef);

  // References to form components
  @ViewChild('userDetailsForm')
  userDetailsForm!: UserDetailsSectionComponent;
  @ViewChild('userRolesForm')
  userRolesForm!: UserRolesSectionComponent;

  private readonly accountsService = inject(AccountsService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);

  // User model to collect data across steps
  newUser = signal<UserCreateRequest>({} as UserCreateRequest);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    this.steps = [
      {
        value: 1,
        header: 'User Details',
        content: this.userDetailsStep,
        complete: false,
        validate: () => this.userDetailsForm.validate(),
      },
      {
        value: 2,
        header: 'User Roles',
        content: this.userRolesStep,
        complete: false,
        validate: () => this.userRolesForm.validate(),
      },
      {
        value: 3,
        header: 'Confirmation',
        content: this.confirmationTemplate,
        complete: true,
      },
    ];
    this.cdr.detectChanges(); // Trigger change detection to update the view
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize user with ownerId
      this.newUser.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  openWizard() {
    this.displayWizard = true;
    this.newUser.set({} as UserCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
  }

  onRolesFormValidityChange(isValid: boolean) {
    this.steps[1].disableNext = !isValid;
  }

  // Update the user state with form data
  updateUserDetails(formData: Record<string, unknown>) {
    this.newUser.update((current) => {
      const updated = { ...current };

      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  updateUserRoles(formData: Record<string, unknown>) {
    this.newUser.update((current) => ({
      ...current,
      roles: formData['roles'] as IdName[],
    }));
  }

  onWizardComplete(): void {
    // Process the final data from all steps
    const userData = this.newUser();

    this.accountsService
      .createUser(userData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: UserResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'user',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          // Handle error, could show message and keep dialog open
          console.error('Error creating user:', error);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newUser.set({} as UserCreateRequest);
    this.dialogRef.close();
  }

  getRoleNames(roles: IdName[] | null | undefined): string {
    if (isEmpty(roles)) {
      return 'No roles assigned';
    }
    return roles?.map((role) => role.name).join(', ') ?? 'No roles assigned';
  }
}
