import { inject, Injectable, signal } from '@angular/core';

import { BaseGridConfig } from '../../../shared/services/base-grid-config';
import { GeoLockProfilesDataAdapter } from '../services/adapters';
import { GeoLockProfileListItem } from '../../../api';
import { isDefined } from '../../../shared/utils';
import {
  DATE_FORMATS,
  FilterCriteria,
  GridColumn,
} from '../../../shared/models';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';

@Injectable({
  providedIn: 'root',
})
export class GeoLockProfilesGridConfig extends BaseGridConfig<GeoLockProfileListItem> {
  private readonly geoLockProfilesService = inject(GeoLockProfilesDataAdapter);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  protected override defaultStateValues = [
    GeoLockProfileListItem.StateEnum.Active,
  ];
  protected override readonly filterState = signal<
    Record<string, FilterCriteria>
  >({
    state: {
      value: this.defaultStateValues,
      operator: 'in',
    },
  });
  protected override params: Record<string, string> = { clientId: '' };
  private readonly stateLabels: Record<
    GeoLockProfileListItem.StateEnum,
    string
  > = {
    active: 'Active',
    deleted: 'Deleted',
  };

  columns: GridColumn<GeoLockProfileListItem>[] = [
    {
      field: 'name',
      header: 'Name',
      filter: true,
      filterType: 'text',
      filterMatchMode: 'contains',
    },
    {
      field: 'state',
      header: 'State',
      valueGetter: (rowData: GeoLockProfileListItem) =>
        isDefined(rowData.state) ? this.stateLabels[rowData.state] : '',
      filter: true,
      filterType: 'multiselect',
      filterMatchMode: 'in',
      filterConfig: {
        type: 'multiselect',
        options: [
          { label: 'Active', value: GeoLockProfileListItem.StateEnum.Active },
          { label: 'Deleted', value: GeoLockProfileListItem.StateEnum.Deleted },
        ],
        defaultSelected: this.defaultStateValues,
      },
    },
    {
      field: 'modifiedDate',
      header: 'Modified',
      filter: false,
      valueGetter: (rowData: GeoLockProfileListItem) =>
        isDefined(rowData.modifiedDate)
          ? this.measurementDateTimeService.formatDateTime(
              new Date(rowData.modifiedDate),
              DATE_FORMATS.DATE_TIME_SECONDS,
            )
          : '',
    },
  ];

  dataService = this.geoLockProfilesService;

  getTitle(): string {
    return 'Geo Lock Profiles';
  }

  onAdd(): void {}
}
