import { CommonModule } from '@angular/common';
import {
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  AssetRatingProfileCreateRequest,
  AssetRatingProfileResponse,
} from '../../../../../api';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { AssetRatingProfileDetailsSectionComponent } from '../asset-rating-profile-details-section/asset-rating-profile-details-section.component';
import { Step } from '../../../../../shared/models';

@Component({
  selector: 'app-asset-rating-profile-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    AssetRatingProfileDetailsSectionComponent,
  ],
  templateUrl: './asset-rating-profile-create-wizard.component.html',
  styleUrl: './asset-rating-profile-create-wizard.component.scss',
})
export class AssetRatingProfileCreateWizardComponent
  implements AfterViewInit, OnInit
{
  @ViewChild('assetRatingProfileDetailsStep')
  assetRatingProfileDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;
  private readonly cdr = inject(ChangeDetectorRef);

  // References to form components
  @ViewChild('assetRatingProfileDetailsForm')
  assetRatingProfileDetailsForm!: AssetRatingProfileDetailsSectionComponent;

  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);

  // AssetRatingProfile model to collect data across steps
  newAssetRatingProfile = signal<AssetRatingProfileCreateRequest>(
    {} as AssetRatingProfileCreateRequest,
  );

  // Form validity state
  formIsValid = signal<boolean>(false);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    this.steps = [
      {
        value: 1,
        header: 'Asset Rating Profile Details',
        content: this.assetRatingProfileDetailsStep,
        complete: false,
        validate: () => this.assetRatingProfileDetailsForm.validate(),
      },
      {
        value: 2,
        header: 'Confirmation',
        content: this.confirmationTemplate,
        complete: true,
      },
    ];
    this.cdr.detectChanges(); // Trigger change detection to update the view
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize assetRatingProfile with ownerId
      this.newAssetRatingProfile.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  openWizard() {
    this.displayWizard = true;
    this.newAssetRatingProfile.set({} as AssetRatingProfileCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  // Update the assetRatingProfile state with form data
  updateAssetRatingProfileDetails(formData: Record<string, unknown>) {
    this.newAssetRatingProfile.update((current) => {
      const updated = { ...current };

      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  onWizardComplete(): void {
    // Process the final data from all steps
    const assetRatingProfileData = this.newAssetRatingProfile();

    this.entitiesService
      .createAssetRatingProfile(assetRatingProfileData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: AssetRatingProfileResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'overspeed-profile',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          // Handle error, could show message and keep dialog open
          console.error('Error creating asset rating profile:', error);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newAssetRatingProfile.set({} as AssetRatingProfileCreateRequest);
    this.dialogRef.close();
  }
}
