import { CommonModule } from '@angular/common';
import {
  Component,
  ViewChild,
  AfterViewInit,
  TemplateRef,
  signal,
  inject,
  OnInit,
  DestroyRef,
} from '@angular/core';
import { ReactiveFormsModule } from '@angular/forms';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { Step } from '../../../../../shared/models';
import { ButtonModule } from 'primeng/button';
import { DeviceDetailsSectionComponent } from '../device-details-section/device-details-section.component';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import {
  DeviceCreateRequest,
  DeviceResponse,
  EntitiesService,
} from '../../../../../api';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { InfoSectionComponent } from '../../shared/info-section/info-section.component';
import { AdminStateService } from '../../../services/admin-state.service';

@Component({
  selector: 'app-device-create-wizard',
  standalone: true,
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    DeviceDetailsSectionComponent,
    InfoSectionComponent,
  ],
  templateUrl: './device-create-wizard.component.html',
  styleUrl: './device-create-wizard.component.scss',
})
export class DeviceCreateWizardComponent implements AfterViewInit, OnInit {
  @ViewChild('deviceDetailsStep') deviceDetailsStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('deviceInfoStep', { static: true })
  deviceInfoStep!: TemplateRef<{ $implicit: Step }> | null;
  @ViewChild('confirmationTemplate', { static: true })
  confirmationTemplate!: TemplateRef<{ $implicit: Step }> | null;

  // References to form components
  @ViewChild('deviceDetailsForm')
  deviceDetailsForm!: DeviceDetailsSectionComponent;
  @ViewChild('deviceInfoForm')
  deviceInfoForm!: InfoSectionComponent<DeviceResponse>;

  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);
  private readonly adminStateService = inject(AdminStateService);
  readonly entityCustomFields = signal<Record<string, string>[]>([]);

  // Device model to collect data across steps
  newDevice = signal<DeviceCreateRequest>({} as DeviceCreateRequest);

  // Form validity state
  formIsValid = signal<boolean>(false);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;

  ngAfterViewInit() {
    setTimeout(() => {
      this.steps = [
        {
          value: 1,
          header: 'Device Details',
          content: this.deviceDetailsStep,
          complete: false,
          validate: () => this.deviceDetailsForm.validate(),
        },
        {
          value: 2,
          header: 'Device Information',
          content: this.deviceInfoStep,
          complete: false,
          validate: () => this.deviceInfoForm.validate(),
        },
        {
          value: 3,
          header: 'Confirmation',
          content: this.confirmationTemplate,
          complete: true,
        },
      ];
    });
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize device with ownerId
      this.newDevice.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }

    const selectedClient = this.adminStateService.selectedClient();

    if (selectedClient) {
      // Update the custom fields signal
      this.entityCustomFields.set([
        ...(selectedClient.customFields?.['device'] ?? []),
      ]);
    }
  }

  openWizard() {
    this.displayWizard = true;
    this.newDevice.set({} as DeviceCreateRequest);
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  onInfoFormValidityChange(isValid: boolean) {
    this.steps[1].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  // Update the device state with form data
  updateDeviceDetails(formData: Record<string, unknown>) {
    this.newDevice.update((current) => {
      const updated = { ...current };

      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  updateDeviceInfo(formData: Record<string, unknown>) {
    this.newDevice.update((current) => {
      const updated = { ...current };

      updated['fields'] = isEmpty(formData['fields'])
        ? undefined
        : (formData as Record<string, Record<string, object>>)['fields'];

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  onWizardComplete(): void {
    // Process the final data from all steps
    const deviceData = this.newDevice();

    this.entitiesService
      .createDevice(deviceData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: DeviceResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'device',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          console.error('Error creating device:', error);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newDevice.set({} as DeviceCreateRequest);
    this.dialogRef.close();
  }
}
